var e={},t=JSON.parse(`{"e100":{"name":"Curcumine","note":"Colorant naturel issu du curcuma.","detail":{"risks":"Le pigment jaune de la racine de curcuma, utilisé depuis des millénaires en cuisine. Mal absorbé par l'organisme et éliminé en grande partie inchangé.","benefits":"","interestingFact":"","research":""}},"e101":{"name":"Riboflavine","note":"Vitamine B2 utilisée comme colorant.","detail":{"risks":"Une vitamine qui fait double emploi comme colorant jaune — la même riboflavine que votre corps utilise pour transformer les aliments en énergie.","benefits":"","interestingFact":"","research":""}},"e102":{"name":"Tartrazine","note":"Colorant azoïque lié à l'hyperactivité chez les enfants ; avertissement obligatoire dans l'EU.","detail":{"risks":"Un colorant azoïque synthétique. L'un des « six de Southampton » que l'essai publié dans le Lancet 2007 a liés à une hyperactivité accrue chez les enfants — les produits de l'EU en contenant doivent porter une mention d'avertissement.","benefits":"","interestingFact":"","research":""}},"e104":{"name":"Jaune de quinoléine","note":"Colorant synthétique lié à l'hyperactivité ; avertissement obligatoire dans l'EU.","detail":{"risks":"Un jaune synthétique restreint dans l'EU après les conclusions de Southampton ; interdit dans l'alimentation aux US, au Canada et au Japon.","benefits":"","interestingFact":"","research":""}},"e110":{"name":"Jaune orangé S","note":"Colorant azoïque lié à l'hyperactivité chez les enfants ; avertissement obligatoire dans l'EU.","detail":{"risks":"Un colorant azoïque dérivé du pétrole figurant parmi les « six de Southampton ». L'EFSA a nettement réduit sa dose journalière admissible en 2009 avant de l'assouplir partiellement après de nouvelles données.","benefits":"","interestingFact":"","research":""}},"e120":{"name":"Cochenille (carmin)","note":"Rouge d'origine insecte ; peut déclencher des réactions allergiques.","detail":{"risks":"Un rouge intense extrait de cochenilles séchées — environ 70 000 insectes sont nécessaires pour 500 g de colorant. Naturel, mais c'est l'un des rares colorants présentant des réactions allergiques documentées (parfois sévères).","benefits":"","interestingFact":"","research":""}},"e122":{"name":"Azorubine","note":"Colorant azoïque lié à l'hyperactivité ; avertissement obligatoire dans l'EU.","detail":{"risks":"Un colorant azoïque synthétique interdit aux US et dans plusieurs autres pays ; les produits de l'EU doivent porter une mention d'avertissement concernant l'hyperactivité.","benefits":"","interestingFact":"","research":""}},"e124":{"name":"Ponceau 4R","note":"Colorant azoïque lié à l'hyperactivité ; avertissement obligatoire dans l'EU.","detail":{"risks":"Un colorant azoïque rouge fraise figurant parmi les « six de Southampton », interdit aux US. L'EFSA a divisé par quatre son apport admissible en 2009.","benefits":"","interestingFact":"","research":""}},"e129":{"name":"Rouge allura AC","note":"Colorant azoïque lié à l'hyperactivité ; avertissement obligatoire dans l'EU.","detail":{"risks":"Le colorant rouge le plus utilisé aux US, et pourtant une mention d'avertissement sur l'hyperactivité est obligatoire dans l'EU. Des études récentes sur les souris débattent également d'effets d'inflammation intestinale à fortes doses.","benefits":"","interestingFact":"","research":""}},"e131":{"name":"Bleu patenté V","note":"Bleu synthétique ; rares réactions allergiques.","detail":{"risks":"Un colorant synthétique également utilisé en médecine pour marquer les ganglions lymphatiques lors des chirurgies — c'est là que son rare potentiel allergique a été documenté pour la première fois.","benefits":"","interestingFact":"","research":""}},"e132":{"name":"Indigotine","note":"Bleu synthétique, généralement bien toléré.","detail":{"risks":"Le cousin synthétique de l'indigo, le colorant qui teint les jeans bleus. Mal absorbé ; l'EFSA n'a trouvé aucun problème de sécurité aux niveaux de consommation rapportés.","benefits":"","interestingFact":"","research":""}},"e133":{"name":"Bleu brillant FCF","note":"Colorant synthétique ; généralement bien toléré aux doses alimentaires.","detail":{"risks":"Un bleu triarylméthane souvent associé à la tartrazine pour obtenir des teintes vertes. Moins de 5% est absorbé ; le reste traverse directement l'organisme.","benefits":"","interestingFact":"","research":""}},"e140":{"name":"Chlorophylles","note":"Pigment vert naturel des plantes.","detail":{"risks":"La même molécule qui rend les feuilles vertes et alimente la photosynthèse, extraite de l'herbe, des orties ou de la luzerne.","benefits":"","interestingFact":"","research":""}},"e141":{"name":"Chlorophyllines au cuivre","note":"Pigment vert naturel stabilisé.","detail":{"risks":"Une chlorophylle dont le cœur de magnésium est remplacé par du cuivre, ce qui maintient la stabilité du vert lors de la cuisson — le cuivre reste lié et non absorbé.","benefits":"","interestingFact":"","research":""}},"e142":{"name":"Vert S","note":"Vert synthétique, restreint dans plusieurs pays.","detail":{"risks":"Un colorant synthétique autorisé dans l'EU (sauce à la menthe, petits pois en conserve) mais interdit au Canada, au Japon et en Norvège. Mal absorbé.","benefits":"","interestingFact":"","research":""}},"e150a":{"name":"Caramel ordinaire","note":"Colorant caramel simple ; la classe de caramel la moins préoccupante.","detail":{"risks":"Fabriqué en chauffant du sucre, tout comme pour le caraméliser dans une poêle, mais de manière contrôlée à l'échelle industrielle. La seule classe de caramel produite sans chimie de l'ammoniaque ni des sulfites.","benefits":"","interestingFact":"","research":""}},"e150b":{"name":"Caramel au sulfite caustique","note":"Caramel fabriqué avec des composés de sulfite.","detail":{"risks":"Caramel produit avec des composés de sulfite, utilisé dans les spiritueux comme le whisky et le brandy. Le sulfite résiduel est négligeable.","benefits":"","interestingFact":"","research":""}},"e150c":{"name":"Caramel ammoniacal","note":"Contient des traces de 4-MEI, débattu à fortes doses.","detail":{"risks":"Caramel fabriqué avec des composés d'ammonium ; le procédé crée des traces de 4-méthylimidazole (4-MEI), qui a provoqué des tumeurs lors d'études à fortes doses chez la souris. L'EFSA estime que la consommation habituelle est sûre, mais a fixé des limites.","benefits":"","interestingFact":"","research":""}},"e150d":{"name":"Caramel au sulfite d'ammonium","note":"Caramel de cola ; contient des traces de 4-MEI, débattu à fortes doses.","detail":{"risks":"Le colorant le plus consommé au monde en volume — c'est lui qui donne au cola sa couleur brune. Même débat sur le 4-MEI que pour le E150c ; la Californie exige des avertissements sur le risque de cancer au-delà de certains seuils, tandis que l'EFSA considère une consommation normale comme sûre.","benefits":"","interestingFact":"","research":""}},"e153":{"name":"Charbon végétal","note":"Colorant noir ; réévalué dans l'EU, débat sur les nanoparticules.","detail":{"risks":"Essentiellement du charbon de bois de qualité alimentaire. L'EFSA a signalé que certains lots contiennent des nanoparticules suffisamment petites pour être absorbées, déclenchant un réexamen en cours de sa pureté.","benefits":"","interestingFact":"","research":""}},"e155":{"name":"Brun HT","note":"Brun azoïque, interdit dans plusieurs pays.","detail":{"risks":"Un brun azoïque synthétique utilisé dans les gâteaux au chocolat ; interdit aux US, au Canada et dans une grande partie de la Scandinavie, mais autorisé dans l'EU dans certaines limites.","benefits":"","interestingFact":"","research":""}},"e160a":{"name":"Carotènes","note":"Pigment orange naturel, provitamine A.","detail":{"risks":"Le pigment des carottes et des potirons ; votre corps le transforme en vitamine A selon ses besoins, stockant l'excès de manière inoffensive dans les graisses (mangez-en suffisamment et votre peau deviendra littéralement orange).","benefits":"","interestingFact":"","research":""}},"e160b":{"name":"Rocou","note":"Colorant naturel issu de graines ; rares réactions de sensibilité.","detail":{"risks":"Un extrait rouge-orangé de graines du rocouyer, utilisé par les Aztèques comme peinture corporelle et aujourd'hui pour colorer le cheddar et le Red Leicester. Des réactions d'hypersensibilité rares sont documentées.","benefits":"","interestingFact":"","research":""}},"e160c":{"name":"Extrait de paprika","note":"Colorant naturel dérivé du poivron.","detail":{"risks":"Un pigment concentré issu de poivrons rouges doux — la même capsanthine qui donne au paprika sa couleur rouge, le piquant en moins.","benefits":"","interestingFact":"","research":""}},"e160d":{"name":"Lycopène","note":"Pigment naturel de la tomate.","detail":{"risks":"Le rouge des tomates et de la pastèque ; également étudié en tant qu'antioxydant à part entière.","benefits":"","interestingFact":"","research":""}},"e161b":{"name":"Lutéine","note":"Pigment naturel de la rose d'Inde.","detail":{"risks":"Un caroténoïde jaune issu des pétales de rose d'Inde, identique à la lutéine concentrée dans la rétine de votre œil.","benefits":"","interestingFact":"","research":""}},"e162":{"name":"Rouge de betterave","note":"Pigment naturel de betterave.","detail":{"risks":"La bétanine, pressée à partir de betteraves. Tellement inoffensive que son principal « effet secondaire » est exactement le même que celui des betteraves.","benefits":"","interestingFact":"","research":""}},"e163":{"name":"Anthocyanes","note":"Pigments naturels de baies/raisins.","detail":{"risks":"La famille des pigments rouge-violet issus de la peau du raisin, des baies et du chou rouge. Ils changent de couleur selon l'acidité — rouge en milieu acide, bleu en milieu alcalin — ce qui explique pourquoi le même additif peut avoir un aspect différent selon les produits.","benefits":"","interestingFact":"","research":""}},"e170":{"name":"Carbonate de calcium","note":"Craie — blanc minéral, également une source de calcium.","detail":{"risks":"Tout simplement de la craie ou du calcaire, utilisé comme colorant blanc de surface et antiagglomérant. C'est le même composé que celui des compléments alimentaires en calcium.","benefits":"","interestingFact":"","research":""}},"e171":{"name":"Dioxyde de titane","note":"Interdit dans l'alimentation dans l'EU depuis 2022 — la génotoxicité n'a pas pu être exclue.","detail":{"risks":"Un pigment minéral d'un blanc éclatant (également présent dans la peinture et les crèmes solaires). L'EFSA ne pouvait plus exclure de dommages à l'ADN causés par l'accumulation de nanoparticules, et l'EU l'a interdit dans l'alimentation en 2022 — toujours légal aux US.","benefits":"","interestingFact":"","research":""}},"e172":{"name":"Oxydes de fer","note":"Pigments minéraux (teintes de rouille).","detail":{"risks":"De l'oxyde de fer purifié — chimiquement, de la rouille contrôlée — donnant des teintes jaunes, rouges et noires. Pratiquement insoluble et non absorbé.","benefits":"","interestingFact":"","research":""}},"e173":{"name":"Aluminium","note":"Colorant métallique de surface ; préoccupation concernant l'apport en aluminium.","detail":{"risks":"De l'aluminium métallique pour des décorations argentées. Contribue à l'apport total en aluminium alimentaire, pour lequel l'EFSA maintient une limite hebdomadaire stricte car il s'accumule dans l'organisme.","benefits":"","interestingFact":"","research":""}},"e174":{"name":"Argent","note":"Colorant métallique décoratif.","detail":{"risks":"De la vraie feuille d'argent, principalement en confiserie (les perles argentées sur les gâteaux). Inerte dans le tube digestif aux doses décoratives.","benefits":"","interestingFact":"","research":""}},"e175":{"name":"Or","note":"Colorant métallique décoratif.","detail":{"risks":"De la vraie feuille d'or. Chimiquement inerte — elle traverse intégralement l'organisme, ce qui en fait l'additif le plus cher qui ne fait exactement rien.","benefits":"","interestingFact":"","research":""}},"e200":{"name":"Acide sorbique","note":"Conservateur doux ; réactions cutanées occasionnelles.","detail":{"risks":"Isolé pour la première fois à partir des baies de sorbier ; bloque la croissance des moisissures et des levures en perturbant leurs enzymes. Votre corps le métabolise comme un acide gras.","benefits":"","interestingFact":"","research":""}},"e201":{"name":"Sorbate de sodium","note":"Sel de l'acide sorbique, conservateur doux.","detail":{"risks":"La forme sodique de l'acide sorbique (présent à l'origine dans les baies de sorbier). Il se dissout mieux dans les aliments aqueux et fonctionne de manière identique — en bloquant les enzymes des moisissures et des levures.","benefits":"","interestingFact":"","research":""}},"e202":{"name":"Sorbate de potassium","note":"Conservateur doux courant.","detail":{"risks":"Le conservateur incontournable du fromage, du vin et des produits de boulangerie — un sel plus soluble de l'acide sorbique (issu à l'origine du sorbier). L'un des conservateurs connus les mieux tolérés.","benefits":"","interestingFact":"","research":""}},"e203":{"name":"Sorbate de calcium","note":"Sel de l'acide sorbique, conservateur doux.","detail":{"risks":"La forme calcique de l'acide sorbique, utilisée lorsqu'un conservateur sans sodium est recherché. Métabolisé comme un acide gras, tout comme le reste de la famille des sorbates.","benefits":"","interestingFact":"","research":""}},"e210":{"name":"Acide benzoïque","note":"Peut former du benzène avec la vitamine C ; déclencheur d'allergies.","detail":{"risks":"Présent à l'état naturel dans les canneberges et la cannelle ; bloque les levures et les bactéries dans les aliments acides. Le piège : combiné à la vitamine C dans les boissons rafraîchissantes, il peut former des traces de benzène, un cancérogène avéré — la raison pour laquelle les recettes ont été reformulées dans les années 2000.","benefits":"","interestingFact":"","research":""}},"e211":{"name":"Benzoate de sodium","note":"Peut former du benzène avec la vitamine C ; lié à l'hyperactivité en combinaison avec des colorants.","detail":{"risks":"Le sel soluble de l'acide benzoïque, classique dans les sodas. L'étude de Southampton l'a testé aux côtés de colorants azoïques et a révélé des effets sur l'hyperactivité en combinaison ; le problème du benzène formé avec la vitamine C s'applique également ici.","benefits":"","interestingFact":"","research":""}},"e212":{"name":"Benzoate de potassium","note":"Conservateur benzoate ; même inquiétude concernant le benzène et la vitamine C.","detail":{"risks":"La forme potassique du benzoate de sodium, choisie pour les recettes pauvres en sodium. Même chimie : efficace contre les levures dans les boissons acides, même mise en garde concernant la formation de benzène avec la vitamine C.","benefits":"","interestingFact":"","research":""}},"e213":{"name":"Benzoate de calcium","note":"Conservateur benzoate ; même inquiétude concernant le benzène et la vitamine C.","detail":{"risks":"La forme calcique de la famille des benzoates, rarement utilisée. Partage les caractéristiques de la famille — ne fonctionne que dans les aliments acides et fait l'objet de la même mise en garde concernant la vitamine C et le benzène.","benefits":"","interestingFact":"","research":""}},"e214":{"name":"Éthylparabène","note":"Conservateur parabène ; débat sur la perturbation endocrinienne.","detail":{"risks":"L'un des rares parabènes encore autorisés dans l'alimentation (rarement utilisé). Les parabènes miment faiblement les œstrogènes dans les études de laboratoire, ce qui les maintient sous surveillance quant aux effets endocriniens.","benefits":"","interestingFact":"","research":""}},"e218":{"name":"Méthylparabène","note":"Conservateur parabène ; débat sur la perturbation endocrinienne.","detail":{"risks":"Un conservateur parabène plus familier en cosmétique, parfois présent dans les glaçages de confiserie. La question endocrinienne — un faible mimétisme œstrogénique dans les études de laboratoire — s'applique à toute la famille des parabènes.","benefits":"","interestingFact":"","research":""}},"e219":{"name":"Méthylparabène sodique","note":"Conservateur parabène ; débat sur la perturbation endocrinienne.","detail":{"risks":"Le sel de sodium hydrosoluble du méthylparabène. Même famille, même surveillance endocrinienne.","benefits":"","interestingFact":"","research":""}},"e220":{"name":"Dioxyde de soufre","note":"Sulfite — un allergène majeur, détruit la vitamine B1.","detail":{"risks":"L'ancien conservateur du vin — les Romains brûlaient des bougies de soufre dans les fûts. Il stoppe le brunissement et les microbes, mais c'est un véritable allergène : environ 3–10% des asthmatiques y réagissent, c'est pourquoi la mention « contient des sulfites » est obligatoire. Il détruit également la thiamine (vitamine B1) dans les aliments.","benefits":"","interestingFact":"","research":""}},"e221":{"name":"Sulfite de sodium","note":"Allergène sulfite.","detail":{"risks":"Un sel de sulfite libérant le même SO₂ actif que l'E220 — même pouvoir antimicrobien, même mise en garde concernant la sensibilité à l'asthme, même étiquetage d'allergène obligatoire.","benefits":"","interestingFact":"","research":""}},"e222":{"name":"Bisulfite de sodium","note":"Allergène sulfite.","detail":{"risks":"Un membre de la famille des sulfites utilisé dans le vin et les aliments au vinaigre. Tous les sulfites partagent la mise en garde concernant les allergènes et la destruction de la vitamine B1 de l'E220.","benefits":"","interestingFact":"","research":""}},"e223":{"name":"Métabisulfite de sodium","note":"Allergène sulfite.","detail":{"risks":"La forme en poudre de la chimie du dioxyde de soufre, courante dans les fruits secs et le vin. Même mise en garde concernant les allergènes que l'E220 — c'est grâce à lui que les abricots secs restent oranges.","benefits":"","interestingFact":"","research":""}},"e224":{"name":"Métabisulfite de potassium","note":"Allergène sulfite.","detail":{"risks":"La « pastille Campden » du vigneron — le sulfite standard pour le vin domestique et commercial. Mêmes mises en garde concernant les allergènes et la vitamine B1 que le reste de la famille.","benefits":"","interestingFact":"","research":""}},"e226":{"name":"Sulfite de calcium","note":"Allergène sulfite.","detail":{"risks":"Un sel de calcium rarement utilisé de la famille des sulfites ; partage la mise en garde concernant la sensibilité à l'asthme et l'étiquetage obligatoire du groupe.","benefits":"","interestingFact":"","research":""}},"e228":{"name":"Bisulfite de potassium","note":"Allergène sulfite.","detail":{"risks":"Un sulfite principalement utilisé dans le vin. Même chimie familiale et même mise en garde concernant les allergènes que l'E220.","benefits":"","interestingFact":"","research":""}},"e234":{"name":"Nisine","note":"Peptide antibactérien naturel issu de la fermentation.","detail":{"risks":"Un peptide produit par les mêmes bactéries que celles qui fermentent le lait — il perce des trous dans les membranes des bactéries d'altération. Utilisé dans le fromage et les conserves ; digéré comme n'importe quelle protéine.","benefits":"","interestingFact":"","research":""}},"e235":{"name":"Natamycine","note":"Antifongique pour croûtes de fromage ; débat sur la classe d'antibiotiques.","detail":{"risks":"Un antifongique issu de bactéries du sol, appliqué sur les croûtes de fromage et les boyaux de saucissons secs. À peine absorbé, mais son utilisation médicale comme antifongique entretient un débat sur la résistance.","benefits":"","interestingFact":"","research":""}},"e239":{"name":"Hexaméthylène tétramine","note":"Conservateur libérant du formaldéhyde (Provolone uniquement).","detail":{"risks":"Autorisé dans l'EU uniquement pour le fromage Provolone. Il agit en libérant lentement du formaldéhyde — raison pour laquelle son utilisation est si strictement limitée.","benefits":"","interestingFact":"","research":""}},"e242":{"name":"Dicarbonate de diméthyle","note":"Stérilisant pour boissons qui se décompose entièrement.","detail":{"risks":"Injecté dans les boissons juste avant l'emballage, il tue les microbes puis s'hydrolyse complètement en de très faibles quantités de méthanol et de CO₂ en quelques heures — il ne reste plus rien au moment où vous le buvez.","benefits":"","interestingFact":"","research":""}},"e249":{"name":"Nitrite de potassium","note":"Nitrite pour viandes transformées ; forme des nitrosamines, voie classée par l'IARC.","detail":{"risks":"Le jumeau potassique du nitrite de sodium (E250) : conserve la couleur rose de la charcuterie et la préserve du botulisme, mais alimente la même chimie des nitrosamines qui sous-tend la classification des viandes transformées par l'IARC.","benefits":"","interestingFact":"","research":""}},"e250":{"name":"Nitrite de sodium","note":"Nitrite pour viandes transformées ; forme des nitrosamines cancérogènes (IARC).","detail":{"risks":"Ce qui rend le jambon rose et bloque le botulisme — la toxine la plus mortelle connue — ce qui explique pourquoi il est toujours autorisé. Mais avec les protéines de la viande et la chaleur, il forme des nitrosamines, au cœur de la raison pour laquelle l'IARC classe la viande transformée comme cancérogène pour l'homme. La France a commencé à en restreindre l'usage en 2023.","benefits":"","interestingFact":"","research":""}},"e251":{"name":"Nitrate de sodium","note":"Se transforme en nitrite ; même inquiétude concernant les nitrosamines.","detail":{"risks":"La forme de réserve de la chimie de salaison : les bactéries présentes dans la viande (et dans votre salive) transforment régulièrement le nitrate en nitrite, alimentant la même voie des nitrosamines que l'E250.","benefits":"","interestingFact":"","research":""}},"e252":{"name":"Nitrate de potassium","note":"Se transforme en nitrite ; même inquiétude concernant les nitrosamines.","detail":{"risks":"Le salpêtre — utilisé pour conserver la viande depuis le Moyen Âge (et pour fabriquer de la poudre à canon). Les bactéries le transforment en nitrite dans la viande, où commence la chimie des nitrosamines.","benefits":"","interestingFact":"","research":""}},"e260":{"name":"Acide acétique","note":"Vinaigre.","detail":{"risks":"L'acide concentré du vinaigre. L'un des plus anciens conservateurs de l'histoire de l'humanité.","benefits":"","interestingFact":"","research":""}},"e261":{"name":"Acétate de potassium","note":"Sel de vinaigre.","detail":{"risks":"L'acide du vinaigre lié au potassium — un régulateur d'acidité que votre corps traite exactement comme du vinaigre.","benefits":"","interestingFact":"","research":""}},"e262":{"name":"Acétates de sodium","note":"Sel de vinaigre — le goût des chips sel & vinaigre.","detail":{"risks":"L'acétate de sodium est ce qui donne aux chips sel et vinaigre leur piquant sans qu'elles deviennent molles. C'est également le composé présent dans les chaufferettes réutilisables.","benefits":"","interestingFact":"","research":""}},"e263":{"name":"Acétate de calcium","note":"Sel de vinaigre.","detail":{"risks":"L'acide du vinaigre lié au calcium ; sert également d'affermissant. Métabolisé comme du vinaigre.","benefits":"","interestingFact":"","research":""}},"e270":{"name":"Acide lactique","note":"Acide de fermentation naturel.","detail":{"risks":"L'acide du yaourt, du pain au levain et des courbatures musculaires — produit par fermentation. L'acide lactique de qualité alimentaire provient de la fermentation du sucre avec la même famille de bactéries que celle du yaourt.","benefits":"","interestingFact":"","research":""}},"e280":{"name":"Acide propionique","note":"Conservateur pour le pain ; effets intestinaux débattus à fortes doses.","detail":{"risks":"Présent à l'état naturel dans le fromage suisse (il donne leur saveur aux trous) et dans votre propre intestin, où les bactéries le produisent à partir des fibres. Utilisé comme conservateur de boulangerie, il stoppe les moisissures ; de petites études débattent de ses effets métaboliques à fortes doses.","benefits":"","interestingFact":"","research":""}},"e281":{"name":"Propionate de sodium","note":"Inhibiteur de moisissures pour le pain.","detail":{"risks":"Le sel de sodium de l'acide propionique — le composé que vos propres bactéries intestinales fabriquent à partir des fibres, permettant ici au pain emballé de rester exempt de moisissures pendant des semaines.","benefits":"","interestingFact":"","research":""}},"e282":{"name":"Propionate de calcium","note":"Conservateur pour le pain ; effets intestinaux débattus à fortes doses.","detail":{"risks":"Le conservateur pour le pain le plus courant au monde. Chimiquement le même propionate que votre intestin produit à partir des fibres ; quelques petites études débattent de ses effets sur l'appétit et le métabolisme lors d'apports élevés.","benefits":"","interestingFact":"","research":""}},"e283":{"name":"Propionate de potassium","note":"Inhibiteur de moisissures pour le pain.","detail":{"risks":"La forme potassique de la famille des propionates, destinée aux pains pauvres en sodium. Même mécanisme anti-moisissure.","benefits":"","interestingFact":"","research":""}},"e284":{"name":"Acide borique","note":"Autorisé uniquement pour le caviar dans l'EU.","detail":{"risks":"Un ancien conservateur désormais interdit dans tous les aliments de l'EU, à une exception près : le véritable caviar d'esturgeon, pour lequel aucune alternative ne préserve les œufs. Restreint en raison de l'accumulation du bore.","benefits":"","interestingFact":"","research":""}},"e285":{"name":"Borax","note":"Autorisé uniquement pour le caviar dans l'UE.","detail":{"risks":"Le sel de sodium de l'acide borique, qui bénéficie d'une unique exemption dans l'UE : le caviar d'esturgeon. Partout ailleurs, c'est un ingrédient de produit nettoyant, pas un ingrédient alimentaire.","benefits":"","interestingFact":"","research":""}},"e290":{"name":"Dioxyde de carbone","note":"Les bulles des boissons gazeuses.","detail":{"risks":"Du simple CO₂ — le même gaz que vous expirez. Dans les boissons, il se dissout sous forme d'acide carbonique, créant le pétillement et le picotement sur la langue ; dans les emballages, il chasse l'oxygène pour que les aliments se conservent plus longtemps. Il quitte votre corps dans un rot.","benefits":"","interestingFact":"","research":""}},"e296":{"name":"Acide malique","note":"Acide de fruit naturel.","detail":{"risks":"L'acide acidulé des pommes vertes — son nom vient de malum, le mot latin pour pomme. C'est aussi la touche très sûre des bonbons ultra-acides.","benefits":"","interestingFact":"","research":""}},"e297":{"name":"Acide fumarique","note":"Acide naturel de type fruit.","detail":{"risks":"Présent à l'état naturel dans les bolets et le lichen ; utilisé là où l'acide malique ou citrique absorberait trop d'humidité, par exemple dans les mélanges en poudre.","benefits":"","interestingFact":"","research":""}},"e300":{"name":"Acide ascorbique","note":"Vitamine C.","detail":{"risks":"De la vitamine C pure. Dans les aliments, il agit comme un piégeur d'oxygène — il se sacrifie à l'oxydation pour éviter que l'aliment ne brunisse. Dans le pain, il renforce le gluten.","benefits":"","interestingFact":"","research":""}},"e301":{"name":"Ascorbate de sodium","note":"Sel de vitamine C.","detail":{"risks":"De la vitamine C liée au sodium pour une meilleure solubilité — un classique de la charcuterie, où il accélère la salaison et inhibe la formation de nitrosamines.","benefits":"","interestingFact":"","research":""}},"e302":{"name":"Ascorbate de calcium","note":"Sel de vitamine C.","detail":{"risks":"De la vitamine C sous sa forme calcique plus douce, utilisée pour empêcher les fruits découpés de brunir. Sur le plan nutritionnel, cela reste de la vitamine C avec un peu de calcium.","benefits":"","interestingFact":"","research":""}},"e304":{"name":"Palmitate d'ascorbyle","note":"Vitamine C liposoluble.","detail":{"risks":"De la vitamine C liée à un acide gras pour pouvoir protéger les huiles et les matières grasses du rancissement, là où la vitamine C classique ne peut pas agir.","benefits":"","interestingFact":"","research":""}},"e306":{"name":"Tocophérols","note":"Vitamine E.","detail":{"risks":"De la vitamine E naturelle extraite d'huiles végétales ; elle empêche les matières grasses de rancir de la même façon qu'elle protège vos membranes cellulaires.","benefits":"","interestingFact":"","research":""}},"e307":{"name":"Alpha-tocophérol","note":"Vitamine E.","detail":{"risks":"La forme spécifique de vitamine E que votre corps préfère, produite par synthèse pour des raisons de régularité. Même rôle antioxydant que l'E306.","benefits":"","interestingFact":"","research":""}},"e308":{"name":"Gamma-tocophérol","note":"Vitamine E.","detail":{"risks":"La forme de vitamine E la plus courante dans l'huile de soja et de maïs, protégeant les graisses de l'oxydation.","benefits":"","interestingFact":"","research":""}},"e309":{"name":"Delta-tocophérol","note":"Vitamine E.","detail":{"risks":"La plus thermostable des molécules de la famille de la vitamine E, privilégiée pour les huiles de friture.","benefits":"","interestingFact":"","research":""}},"e310":{"name":"Gallate de propyle","note":"Antioxydant synthétique ; débat endocrinien.","detail":{"risks":"Un antioxydant de synthèse pour graisses et huiles. Des études sur rongeurs ont soulevé des questions (contestées) sur des effets endocriniens et tumoraux ; l'EFSA a réévalué sa dose journalière en 2014, et il apparaît de moins en moins dans les recettes modernes.","benefits":"","interestingFact":"","research":""}},"e311":{"name":"Gallate d'octyle","note":"Antioxydant synthétique ; données limitées.","detail":{"risks":"Un antioxydant de la famille des gallates dont l'autorisation dans l'UE a expiré en 2018 faute de données de sécurité — sa présence sur une étiquette indique généralement une formule ancienne ou un produit importé.","benefits":"","interestingFact":"","research":""}},"e312":{"name":"Gallate de dodécyle","note":"Antioxydant synthétique ; données limitées.","detail":{"risks":"Le gallate à la chaîne la plus longue ; comme pour l'E311, son autorisation dans l'UE a été retirée en 2018 lorsque les producteurs n'ont fourni aucune donnée justificative.","benefits":"","interestingFact":"","research":""}},"e315":{"name":"Acide érythorbique","note":"Molécule miroir de la vitamine C, antioxydant uniquement.","detail":{"risks":"Un isomère image dans un miroir de la vitamine C : même pouvoir antioxydant dans les aliments, mais presque aucune activité vitaminique dans l'organisme.","benefits":"","interestingFact":"","research":""}},"e316":{"name":"Érythorbate de sodium","note":"Antioxydant utilisé en charcuterie.","detail":{"risks":"Accélère la salaison et réduit la quantité de nitrite nécessaire dans les viandes transformées — sa présence signifie généralement moins de nitrites, pas plus de risques. Le vieux mythe selon lequel il serait « fabriqué à partir de vers de terre » est exactement cela, un mythe (il est produit à partir de sucre).","benefits":"","interestingFact":"","research":""}},"e319":{"name":"TBHQ","note":"Antioxydant synthétique ; études sur l'immunité débattues.","detail":{"risks":"La tert-butylhydroquinone, un antioxydant dérivé du pétrole présent dans les huiles de friture et les nouilles instantanées. Des études sur les animaux à forte dose débattent d'effets immunitaires et tumoraux ; l'EFSA maintient une limite d'exposition stricte.","benefits":"","interestingFact":"","research":""}},"e320":{"name":"BHA","note":"Cancérogène possible (IARC 2B) ; préoccupations endocriniennes.","detail":{"risks":"L'hydroxyanisole butylé, un antioxydant de synthèse. L'IARC le classe comme « peut-être cancérogène » en raison de tumeurs du pré-estomac chez les rongeurs ; il figure également sur la liste de surveillance des perturbateurs endocriniens de l'UE. La vitamine E fait exactement le même travail.","benefits":"","interestingFact":"","research":""}},"e321":{"name":"BHT","note":"Cancérogénicité et effets endocriniens débattus.","detail":{"risks":"Le cousin chimique du BHA, également utilisé dans les cosmétiques et le carburant pour avions. Les preuves sont plus mitigées que pour le BHA — certaines études suggèrent même des effets protecteurs —, mais le débat endocrinien le maintient sous surveillance.","benefits":"","interestingFact":"","research":""}},"e322":{"name":"Lécithines","note":"Émulsifiant naturel issu du soja ou du tournesol.","detail":{"risks":"La molécule qui permet au gras et à l'eau de se mélanger — une extrémité aime l'eau, l'autre aime l'huile. Extraite du soja, des graines de tournesol ou du jaune d'œuf (la mayonnaise tient grâce à la lécithine d'œuf). Vos propres membranes cellulaires en sont en partie constituées.","benefits":"","interestingFact":"","research":""}},"e325":{"name":"Lactate de sodium","note":"Sel de l'acide lactique.","detail":{"risks":"Acide de fermentation lié au sodium — un agent rétenteur d'humidité et conservateur doux pour les viandes et la boulangerie. Vos muscles produisent ce même lactate pendant l'effort.","benefits":"","interestingFact":"","research":""}},"e326":{"name":"Lactate de potassium","note":"Sel de l'acide lactique.","detail":{"risks":"La forme potassique du lactate, courante dans les produits carnés pauvres en sodium. Métabolisé comme le lactate produit par votre propre organisme.","benefits":"","interestingFact":"","research":""}},"e327":{"name":"Lactate de calcium","note":"Sel de l'acide lactique, également une source de calcium.","detail":{"risks":"De l'acide lactique associant du calcium — utilisé pour raffermir les légumes en conserve et même pour enrichir les aliments en calcium. C'est le cristal croustillant que l'on aperçoit parfois sur le cheddar affiné.","benefits":"","interestingFact":"","research":""}},"e330":{"name":"Acide citrique","note":"Acide naturel omniprésent.","detail":{"risks":"L'acide du citron, produit industriellement par fermentation de sucre avec une moisissure (un procédé découvert en 1917). Chaque cellule de votre corps produit et brûle de l'acide citrique en continu — le « cycle de l'acide citrique » est le moyen par lequel vous générez de l'énergie. La rumeur tenace selon laquelle « l'E330 provoque le cancer » remonte à un tract canular des années 1970, l'une des plus anciennes fausses informations alimentaires.","benefits":"","interestingFact":"","research":""}},"e331":{"name":"Citrates de sodium","note":"Sel de l'acide citrique.","detail":{"risks":"Le sel de l'acide citrique — c'est ce qui permet au fromage fondu de fondre de manière homogène sans déphaser, en relâchant le calcium qui maintient liées les protéines de caséine.","benefits":"","interestingFact":"","research":""}},"e332":{"name":"Citrates de potassium","note":"Sel de l'acide citrique.","detail":{"risks":"Un citrate apportant du potassium au lieu du sodium ; un tampon d'acidité métabolisé dans le même cycle énergétique que l'acide citrique lui-même.","benefits":"","interestingFact":"","research":""}},"e333":{"name":"Citrates de calcium","note":"Sel de l'acide citrique, également une source de calcium.","detail":{"risks":"Du citrate lié au calcium — régulateur d'acidité, agent de raffermissement, et forme de calcium utilisée dans de nombreux compléments alimentaires car il est bien absorbé.","benefits":"","interestingFact":"","research":""}},"e334":{"name":"Acide tartrique","note":"Acide naturel du raisin.","detail":{"risks":"L'acide du raisin et du vin — les cristaux parfois présents au fond d'une bouteille de vin sont son sel de potassium. C'est l'acide classique de la levure chimique.","benefits":"","interestingFact":"","research":""}},"e335":{"name":"Tartrates de sodium","note":"Sel de l'acide du raisin.","detail":{"risks":"Acide du raisin lié au sodium, un régulateur d'acidité principalement présent dans les confitures et gelées. Largement non absorbé.","benefits":"","interestingFact":"","research":""}},"e336":{"name":"Tartrates de potassium","note":"Crème de tartre.","detail":{"risks":"La crème de tartre — littéralement grattée de l'intérieur des fûts de vin. Le partenaire traditionnel du bicarbonate de soude dans la levure chimique et le stabilisant des blancs d'œufs en neige.","benefits":"","interestingFact":"","research":""}},"e337":{"name":"Tartrate de sodium et de potassium","note":"Sel de Seignette, issu de la vinification.","detail":{"risks":"Le sel de Seignette, synthétisé pour la première fois par un apothicaire français en 1675. Une célébrité de la cristallographie (ce fut le premier matériau à s'avérer piézoélectrique) qui travaille discrètement comme régulateur d'acidité.","benefits":"","interestingFact":"","research":""}},"e338":{"name":"Acide phosphorique","note":"Acide du cola ; un apport élevé en phosphates est lié à des préoccupations cardiovasculaires.","detail":{"risks":"Ce qui donne au cola son goût très vif (et sa fameuse capacité à dérouiller les objets). L'inquiétude ne porte pas sur une toxicité aiguë mais sur la charge totale en phosphates : la réévaluation de l'EFSA en 2019 a révélé que les grands consommateurs peuvent dépasser la dose sans risque, et qu'un excès de phosphate est lié à un stress vasculaire et rénal.","benefits":"","interestingFact":"","research":""}},"e339":{"name":"Phosphates de sodium","note":"Un apport élevé en phosphates est lié à des préoccupations cardiovasculaires.","detail":{"risks":"Sels de phosphate polyvalents — rétention d'eau, fonte, effet tampon. Sûrs individuellement, mais ils se cumulent : la réévaluation de l'EFSA en 2019 a averti que l'apport total en phosphates issus des aliments transformés peut dépasser les seuils de sécurité.","benefits":"","interestingFact":"","research":""}},"e340":{"name":"Phosphates de potassium","note":"Préoccupation liée à un apport élevé en phosphates.","detail":{"risks":"La branche potassique de la famille des phosphates, courante dans les boissons de l'effort et les fromages fondus. Mêmes mises en garde quant à la charge cumulative en phosphates que pour ses équivalents.","benefits":"","interestingFact":"","research":""}},"e341":{"name":"Phosphates de calcium","note":"Phosphate ; apports modérés acceptables.","detail":{"risks":"Le minéral dont sont faits vos os et vos dents, utilisé comme agent levant et fortifiant en calcium. Le membre le plus doux de la famille des phosphates — le calcium compense en partie l'inquiétude liée à la charge en phosphate.","benefits":"","interestingFact":"","research":""}},"e343":{"name":"Phosphates de magnésium","note":"Phosphate ; apports modérés acceptables.","detail":{"risks":"Un phosphate apportant du magnésium, utilisé comme antiagglomérant et correcteur d'acidité. Il contribue à la charge en phosphate, mais les niveaux d'utilisation typiques sont minimes.","benefits":"","interestingFact":"","research":""}},"e350":{"name":"Malates de sodium","note":"Sel de l'acide malique.","detail":{"risks":"De l'acide malique lié au sodium — un tampon d'acidité métabolisé comme l'acide malique de n'importe quelle pomme.","benefits":"","interestingFact":"","research":""}},"e351":{"name":"Malate de potassium","note":"Sel de l'acide malique.","detail":{"risks":"La forme potassique de l'acide malique, un correcteur d'acidité rarement utilisé et sans problème connu.","benefits":"","interestingFact":"","research":""}},"e352":{"name":"Malates de calcium","note":"Sel de l'acide malique.","detail":{"risks":"De l'acide malique combiné au calcium ; correcteur d'acidité et affermissant, métabolisé comme l'acide d'un fruit.","benefits":"","interestingFact":"","research":""}},"e353":{"name":"Acide métatartrique","note":"Stabilisant pour le vin issu de l'acide du raisin.","detail":{"risks":"Des molécules d'acide du raisin liées en courtes chaînes ; les vignerons l'ajoutent pour empêcher la formation de cristaux de tartre inoffensifs dans la bouteille. Il redevient lentement de l'acide tartrique simple.","benefits":"","interestingFact":"","research":""}},"e355":{"name":"Acide adipique","note":"Acide acidulé synthétique pour poudres.","detail":{"risks":"Un acide acidulé qui insensibilise à l'humidité, ce qui le rend idéal pour les préparations en poudre pour boissons et les desserts en gelée. Dans l'industrie, il est surtout connu comme précurseur du nylon ; son usage alimentaire est une fraction négligeable de sa production.","benefits":"","interestingFact":"","research":""}},"e363":{"name":"Acide succinique","note":"Acide de fermentation.","detail":{"risks":"Un acide issu du même cycle énergétique que le citrate — vos cellules en fabriquent constamment. En alimentation, il relève le goût des desserts en poudre ; son nom vient de l'ambre (succinum), dont il a été extrait pour la première fois par distillation.","benefits":"","interestingFact":"","research":""}},"e380":{"name":"Citrate triammonique","note":"Correcteur d'acidité type citrate.","detail":{"risks":"De l'acide citrique neutralisé par de l'ammonium, utilisé pour réguler l'acidité dans le fromage fondu. L'ammonium s'intègre au traitement normal de l'azote par votre organisme.","benefits":"","interestingFact":"","research":""}},"e385":{"name":"EDTA calcium disodique","note":"Chélateur ; inquiétudes concernant l'absorption des minéraux à fortes doses.","detail":{"risks":"Une pince moléculaire qui saisit les traces de métaux pour qu'elles ne puissent pas catalyser le rancissement ou la coloration (il maintient les pois chiches en conserve bien pâles). Cette même préhension peut lier les minéraux alimentaires, d'où des limites de dose. Également utilisé en médecine contre l'empoisonnement aux métaux lourds.","benefits":"","interestingFact":"","research":""}},"e392":{"name":"Extraits de romarin","note":"Antioxydant végétal naturel.","detail":{"risks":"Des antioxydants concentrés (acide carnosique) issus des feuilles de romarin — le substitut moderne à étiquette propre pour remplacer BHA/BHT.","benefits":"","interestingFact":"","research":""}},"e400":{"name":"Acide alginique","note":"Épaississant issu d'algues brunes.","detail":{"risks":"La gomme structurelle du varech brun — ce qui permet aux algues de rester souples sous l'eau. Dans votre intestin, il se comporte comme une fibre soluble.","benefits":"","interestingFact":"","research":""}},"e401":{"name":"Alginate de sodium","note":"Épaississant issu d'algues.","detail":{"risks":"Issu du varech brun ; célèbre comme ingrédient de « sphérification » en gastronomie moléculaire qui transforme les liquides en perles semblables à du caviar. C'est aussi le gel présent dans de nombreux remèdes contre les brûlures d'estomac.","benefits":"","interestingFact":"","research":""}},"e402":{"name":"Alginate de potassium","note":"Épaississant issu d'algues.","detail":{"risks":"La forme potassique de l'alginate de varech ; un épaississant de type fibre soluble sans problème connu.","benefits":"","interestingFact":"","research":""}},"e404":{"name":"Alginate de calcium","note":"Gélifiant issu d'algues.","detail":{"risks":"De l'alginate de varech préchargé en calcium qui le fait gélifier — également utilisé dans les pansements pour cette même propriété gélifiante.","benefits":"","interestingFact":"","research":""}},"e405":{"name":"Alginate de propylène glycol","note":"Épaississant d'algue modifié (mousse de bière, vinaigrettes).","detail":{"risks":"De l'alginate de varech modifié pour résister à l'acide — c'est ce qui maintient la tenue de la mousse de bière et épaissit les vinaigrettes. La partie propylène glycol est libérée et métabolisée sans danger.","benefits":"","interestingFact":"","research":""}},"e406":{"name":"Agar-agar","note":"Gélifiant issu d'algues.","detail":{"risks":"Issu d'algues rouges — découvert en 1658 au Japon, c'est la gelée standard des laboratoires de microbiologie du monde entier. Il prend de manière plus ferme que la gélatine et reste solide à température ambiante ; entièrement d'origine végétale.","benefits":"","interestingFact":"","research":""}},"e407":{"name":"Carraghénane","note":"Lien débattu avec l'inflammation intestinale sous forme dégradée.","detail":{"risks":"Extrait de l'algue mousse d'Irlande, utilisé depuis des siècles dans les flans au lait irlandais. Le débat : le carraghénane dégradé (pas la forme alimentaire) enflamme l'intestin des animaux, et la question de savoir si l'acide stomacal dégrade la forme alimentaire reste contestée. L'EFSA a renouvelé son autorisation en 2018 mais a demandé plus de données.","benefits":"","interestingFact":"","research":""}},"e407a":{"name":"Algues Eucheuma transformées","note":"Carraghénane semi-raffiné ; même débat.","detail":{"risks":"Un carraghénane moins purifié provenant directement de la culture d'algues Eucheuma, conservant de la cellulose. Il partage point par point le débat sur la dégradation du carraghénane.","benefits":"","interestingFact":"","research":""}},"e410":{"name":"Gomme de caroube","note":"Épaississant naturel de caroube.","detail":{"risks":"Graines moulues du caroubier. Le saviez-vous ? Le poids uniforme des graines de caroube nous a donné le « carat » des bijoutiers.","benefits":"","interestingFact":"","research":""}},"e412":{"name":"Gomme de guar","note":"Épaississant naturel.","detail":{"risks":"Graines de guar moulues d'Inde — huit fois le pouvoir épaississant de la fécule de maïs. Il s'agit d'une fibre soluble ; de très grandes quantités agissent comme n'importe quel excès de fibres.","benefits":"","interestingFact":"","research":""}},"e413":{"name":"Gomme adragante","note":"Gomme naturelle de sève d'arbre.","detail":{"risks":"Sève séchée d'arbustes astragales du Moyen-Orient, récoltée depuis l'Antiquité — Théophraste la décrivait déjà en 300 BC. Le rigidifiant traditionnel des fleurs en sucre sur les gâteaux de mariage.","benefits":"","interestingFact":"","research":""}},"e414":{"name":"Gomme d'acacia","note":"Gomme arabique naturelle.","detail":{"risks":"Sève de l'acacia, récoltée comme le sirop d'érable, principalement au Soudan. C'est elle qui maintient les huiles d'agrumes en suspension dans les sodas et donne de la fermeté aux bonbons. Comptabilisée comme fibre soluble.","benefits":"","interestingFact":"","research":""}},"e415":{"name":"Gomme xanthane","note":"Épaississant issu de fermentation.","detail":{"risks":"Produite par la fermentation du sucre avec la bactérie Xanthomonas. Son superpouvoir est la « fluidification par cisaillement » : épaisse au repos, liquide lorsqu'on l'agite — voilà pourquoi la vinaigrette coule mais ne se sépare pas. Un incontournable de la pâtisserie sans gluten.","benefits":"","interestingFact":"","research":""}},"e416":{"name":"Gomme karaya","note":"Gomme d'arbre ; laxatif doux à fortes doses.","detail":{"risks":"Sève de l'arbre Sterculia d'Inde. Fibre en grande partie indigeste — c'est aussi pourquoi de grandes quantités ont un effet laxatif.","benefits":"","interestingFact":"","research":""}},"e417":{"name":"Gomme tara","note":"Épaississant naturel de graines.","detail":{"risks":"Graines moulues du tara péruvien — cousin plus doux des gommes de guar et de caroube, se comportant comme une fibre soluble.","benefits":"","interestingFact":"","research":""}},"e418":{"name":"Gomme gellane","note":"Gélifiant issu de fermentation.","detail":{"risks":"Fabriquée par fermentation bactérienne comme le xanthane, mais elle gélifie au lieu d'épaissir — c'est elle qui suspend la pulpe dans certains jus et fige les gelées végétaliennes avec une consistance particulièrement nette.","benefits":"","interestingFact":"","research":""}},"e420":{"name":"Sorbitol","note":"Édulcorant polyol ; laxatif à fortes doses.","detail":{"risks":"Un alcool de sucre présent naturellement dans les baies de sorbier et les poires. Deux fois moins calorique que le sucre et respectueux des dents, mais le sorbitol non absorbé fermente dans le côlon — la raison pour laquelle les paquets de chewing-gums sans sucre mettent en garde contre les effets laxatifs.","benefits":"","interestingFact":"","research":""}},"e421":{"name":"Mannitol","note":"Polyol ; laxatif à fortes doses.","detail":{"risks":"Un alcool de sucre extrait à l'origine du frêne à manne (d'où son nom biblique). À peine absorbé, la mise en garde digestive standard sur les polyols s'applique ; sa fondante sensation de fraîcheur fait la fraîcheur de certains bonbons à la menthe.","benefits":"","interestingFact":"","research":""}},"e422":{"name":"Glycérol","note":"Humectant qui préserve l'humidité des aliments.","detail":{"risks":"La molécule colonne vertébrale de tous les lipides, libérée chaque fois que le gras est digéré. Dans les aliments, il retient l'humidité — c'est pourquoi les barres protéinées restent moelleuses pendant des mois.","benefits":"","interestingFact":"","research":""}},"e425":{"name":"Konjac","note":"Restreint dans les confiseries en gelée (risque d'étouffement).","detail":{"risks":"Farine de racine à l'origine des nouilles shirataki japonaises. Son gel est si ferme et stable à la chaleur que l'EU l'a interdit dans les mini-cups de gelée après des décès par étouffement — utilisé comme épaississant alimentaire sous des formats classiques, il ne pose aucun problème.","benefits":"","interestingFact":"","research":""}},"e426":{"name":"Hémicellulose de soja","note":"Émulsifiant à base de fibres de soja.","detail":{"risks":"Fibre soluble extraite de la pulpe de soja, empêchant les boissons lactées acides de cailler. Les consommateurs allergiques au soja doivent noter cette origine.","benefits":"","interestingFact":"","research":""}},"e432":{"name":"Polysorbate 20","note":"Émulsifiant synthétique ; études sur le microbiome controversées.","detail":{"risks":"Le plus petit des émulsifiants-détergents polysorbates. Cette famille a fait l'objet d'examens attentifs après des études sur les souris en 2015 montrant un amincissement de la couche de mucus intestinal ; la pertinence pour l'être humain est toujours en cours d'évaluation.","benefits":"","interestingFact":"","research":""}},"e433":{"name":"Polysorbate 80","note":"Émulsifiant synthétique ; études sur le microbiome controversées.","detail":{"risks":"Un émulsifiant aux propriétés détergentes (glaces, sauces). Une étude largement citée de Nature 2015 a révélé qu'il affinait la couche de mucus protectrice de l'intestin chez la souris, favorisant l'inflammation — la pertinence chez l'humain est toujours à l'étude, mais cela a mis les émulsifiants sur le radar des chercheurs.","benefits":"","interestingFact":"","research":""}},"e434":{"name":"Polysorbate 40","note":"Émulsifiant synthétique ; études sur le microbiome controversées.","detail":{"risks":"Un émulsifiant polysorbate à chaîne moyenne. Il partage le débat de sa famille sur le microbiome ouvert par l'étude Nature 2015 sur les souris.","benefits":"","interestingFact":"","research":""}},"e435":{"name":"Polysorbate 60","note":"Émulsifiant synthétique ; études sur le microbiote débattues.","detail":{"risks":"Le polysorbate le plus utilisé dans les crèmes pâtissières et les garnitures fouettées — il empêche les gouttelettes de matière grasse de fusionner. Comme ses semblables, il est pris dans la tourmente des recherches sur le microbiote intestinal déclenchées par l'étude Nature 2015.","benefits":"","interestingFact":"","research":""}},"e436":{"name":"Polysorbate 65","note":"Émulsifiant synthétique ; études sur le microbiote débattues.","detail":{"risks":"Le polysorbate le plus lourd, présent principalement dans les glaces. Même famille, mêmes questions ouvertes sur le microbiote.","benefits":"","interestingFact":"","research":""}},"e440":{"name":"Pectine","note":"Gélifiant naturel de fruit.","detail":{"risks":"Le gel naturel des pommes et des zestes d'agrumes — ce qui fait prendre la confiture. C'est une fibre soluble, et la raison pour laquelle grand-mère ajoutait des tranches de pomme aux confitures trop liquides.","benefits":"","interestingFact":"","research":""}},"e441":{"name":"Gélatine","note":"Gélifiant d'origine animale.","detail":{"risks":"Du collagène issu de la peau et des os d'animaux, dégradé en une protéine qui fond exactement à la température de la bouche — le « fondant en bouche » des oursons en gomme est une propriété matérielle, pas un arôme.","benefits":"","interestingFact":"","research":""}},"e442":{"name":"Phosphatides d'ammonium","note":"Émulsifiant pour le chocolat, alternative à la lécithine.","detail":{"risks":"Un cousin synthétique de la lécithine fabriqué à partir d'huile de colza, effectuant le même travail dans le chocolat — lui permettre de couler avec moins de beurre de cacao. Digéré comme du gras ordinaire avec une trace de phosphate.","benefits":"","interestingFact":"","research":""}},"e444":{"name":"Acéto-isobutyrate de sucrose","note":"Stabilisant de turbidité pour boissons aux agrumes.","detail":{"risks":"Une molécule alourdie dérivée du sucre qui maintient les huiles d'arôme d'agrumes en suspension trouble et uniforme dans les sodas, au lieu de former un anneau autour du col de la bouteille.","benefits":"","interestingFact":"","research":""}},"e445":{"name":"Esters glycériques de résine de bois","note":"Maintient les huiles d'agrumes mélangées dans les boissons.","detail":{"risks":"De la résine de pin purifiée (la même matière première que les violonistes frottent sur leur archet) estérifiée pour maintenir les huiles d'arôme d'agrumes en suspension dans les boissons pour sportifs.","benefits":"","interestingFact":"","research":""}},"e450":{"name":"Diphosphates","note":"Additif phosphaté ; débat cardiovasculaire en cas d'apports élevés.","detail":{"risks":"L'agent levant phare de la poudre à lever et le liant d'eau dans les viandes transformées et les fromages. Individuellement sûr, mais la réévaluation de l'EFSA de 2019 a averti que l'apport total en phosphates provenant de tous les additifs peut dépasser les seuils de sécurité pour les grands consommateurs — les phosphates sont le « sel caché » des aliments ultra-transformés.","benefits":"","interestingFact":"","research":""}},"e451":{"name":"Triphosphates","note":"Préoccupation liée aux additifs phosphatés.","detail":{"risks":"Des chaînes de phosphate à trois unités qui permettent à la viande et au poisson en saumure de retenir l'eau (et le poids). Ils s'ajoutent à la charge cumulative de phosphate signalée par l'EFSA en 2019.","benefits":"","interestingFact":"","research":""}},"e452":{"name":"Polyphosphates","note":"Préoccupation liée aux additifs phosphatés.","detail":{"risks":"De longues chaînes de phosphate — les liants d'eau les plus puissants de la famille, fréquents dans le glaçage des produits de la mer surgelés et le fromage fondu. Même mise en garde sur l'apport cumulé que pour les autres phosphates.","benefits":"","interestingFact":"","research":""}},"e459":{"name":"Bêta-cyclodextrine","note":"Support d'arôme dérivé de l'amidon.","detail":{"risks":"Un anneau d'unités de glucose doté d'un centre creux qui piège les molécules d'arôme et les libère lentement — un emballage moléculaire fabriqué à partir d'amidon.","benefits":"","interestingFact":"","research":""}},"e460":{"name":"Cellulose","note":"Fibre végétale.","detail":{"risks":"Fibre végétale purifiée, généralement issue de la pâte de bois — de la matière indigeste qui apporte de l'onctuosité et empêche le fromage râpé de s'agglomérer.","benefits":"","interestingFact":"","research":""}},"e461":{"name":"Méthylcellulose","note":"Fibre végétale modifiée ; gélifie à chaud.","detail":{"risks":"Une cellulose chimiquement modifiée avec une particularité surprenante : elle gélifie lorsqu'elle est chauffée et fond lorsqu'elle refroidit — l'inverse de la gélatine. C'est ce qui maintient les burgers végétaux amalgamés sur le gril.","benefits":"","interestingFact":"","research":""}},"e463":{"name":"Hydroxypropylcellulose","note":"Fibre végétale modifiée.","detail":{"risks":"Une cellulose modifiée pour plus de souplesse, utilisée principalement comme enrobage et liant. Traverse le système digestif sans être digérée, comme n'importe quelle fibre.","benefits":"","interestingFact":"","research":""}},"e464":{"name":"Hypromellose","note":"Fibre végétale modifiée (aussi gélules végétariennes).","detail":{"risks":"La cellulose modifiée dont sont faites les gélules de médicaments végétariennes ; dans l'alimentation, elle épaissit et stabilise. Indigeste et non absorbée.","benefits":"","interestingFact":"","research":""}},"e465":{"name":"Éthylméthylcellulose","note":"Fibre végétale modifiée.","detail":{"risks":"Une cellulose doublement modifiée utilisée pour stabiliser les mousses et les émulsions. Comme le reste de la famille des celluloses, elle est éliminée sous forme de fibres.","benefits":"","interestingFact":"","research":""}},"e466":{"name":"Carboxyméthylcellulose","note":"Émulsifiant aux effets débattus sur le microbiote intestinal.","detail":{"risks":"Une cellulose modifiée utilisée dans tout, de la glace au dentifrice. Présente avec le polysorbate 80 dans l'étude Nature 2015 sur le microbiote ; un essai clinique restreint chez l'humain en 2021 a également montré des modifications des bactéries intestinales, la maintenant sous recherche active.","benefits":"","interestingFact":"","research":""}},"e468":{"name":"CMC réticulée","note":"Cellulose modifiée.","detail":{"risks":"De la carboxyméthylcellulose dont les chaînes sont liées entre elles pour qu'elle gonfle plutôt que de se dissoudre — principalement un désintégrant pour comprimés, parfois dans les aliments. Non absorbée.","benefits":"","interestingFact":"","research":""}},"e470a":{"name":"Sels d'acides gras","note":"Sels d'acides gras alimentaires similaires au savon.","detail":{"risks":"Des molécules de gras ordinaires liées au sodium, au potassium ou au calcium — techniquement du savon, pratiquement un antiagglomérant et un agent de démoulage digéré comme du gras.","benefits":"","interestingFact":"","research":""}},"e470b":{"name":"Sels de magnésium d'acides gras","note":"Sel de gras antiagglomérant.","detail":{"risks":"Le stéarate de magnésium, bien connu dans presque tous les comprimés jamais fabriqués — il empêche les poudres de coller aux machines. Digéré comme du gras avec une empreinte infime de magnésium.","benefits":"","interestingFact":"","research":""}},"e471":{"name":"Mono- et diglycérides d'acides gras","note":"Émulsifiant courant ; peut contenir des gras trans.","detail":{"risks":"L'émulsifiant le plus utilisé au monde — des molécules de gras partielles qui font le pont entre l'huile et l'eau, gardant le pain moelleux et la margarine lisse. Chimiquement identiques aux produits normaux de la digestion des graisses ; la nuance est que la production industrielle peut laisser des traces de gras trans, invisibles sur l'étiquette.","benefits":"","interestingFact":"","research":""}},"e472a":{"name":"Esters acétiques des mono- et diglycérides d'acides gras","note":"Émulsifiant pour enrobages et foisonnement.","detail":{"risks":"Émulsifiant E471 auquel est attaché de l'acide acétique (vinaigre) — utilisé dans les glaçages de gâteaux et les crèmes en aérosol. Digéré en gras ordinaire et en vinaigre.","benefits":"","interestingFact":"","research":""}},"e472b":{"name":"Esters lactiques des mono- et diglycérides d'acides gras","note":"Émulsifiant pour crème fouettée.","detail":{"risks":"L'E471 auquel est attaché de l'acide lactique, stabilisant les garnitures fouettées. Se décompose en produits normaux de digestion des graisses et en lactate.","benefits":"","interestingFact":"","research":""}},"e472c":{"name":"Esters citriques des mono- et diglycérides d'acides gras","note":"Émulsifiant, également anti-éclaboussures dans les matières grasses.","detail":{"risks":"L'E471 auquel est attaché de l'acide citrique ; il empêche la margarine d'éclabousser dans la poêle. Digéré en gras et en citrate — tous deux des métabolites du quotidien.","benefits":"","interestingFact":"","research":""}},"e472e":{"name":"DATEM","note":"Émulsifiant pour le pain, généralement bien toléré.","detail":{"risks":"Esters mono- et diacétyltartriques des mono- et diglycérides d'acides gras — le renforçateur de gluten de la boulangerie industrielle qui donne au pain de supermarché sa mie régulière et son volume.","benefits":"","interestingFact":"","research":""}},"e473":{"name":"Sucroesters","note":"Émulsifiant, acceptable aux doses typiques.","detail":{"risks":"Du sucre lié à des acides gras — un émulsifiant assez doux pour que des composés apparentés soient étudiés comme ingrédients pour la préparation pour nourrissons. Se sépare à nouveau en sucre et en gras pendant la digestion.","benefits":"","interestingFact":"","research":""}},"e475":{"name":"Esters polyglycériques d'acides gras","note":"Émulsifiant pour gâteaux.","detail":{"risks":"Des chaînes de glycérol portant des acides gras, incorporant de l'air dans les gâteaux industriels afin de nécessiter moins d'œufs. Digéré comme du gras.","benefits":"","interestingFact":"","research":""}},"e476":{"name":"Polyricinoléate de polyglycérol","note":"Émulsifiant pour le chocolat (PGPR) ; acceptable selon l'EFSA aux doses typiques.","detail":{"risks":"Fabriqué à partir d'huile de ricin, le PGPR rend le chocolat fondu plus fluide afin que les fabricants puissent utiliser du beurre de cacao moins coûteux. Sa présence est un indicateur de coût, pas de santé — l'EFSA le juge sûr à des doses bien supérieures à une consommation réaliste.","benefits":"","interestingFact":"","research":""}},"e477":{"name":"Esters de propylène glycol d'acides gras","note":"Émulsifiant pour garnitures fouettées.","detail":{"risks":"Des acides gras fixés sur une structure de propylène glycol, aérant les garnitures fouettées et les préparations pour gâteaux. Les deux moitiés sont des métabolites courants aux doses alimentaires.","benefits":"","interestingFact":"","research":""}},"e479b":{"name":"Huile de soja oxydée par chauffage interagissant avec des mono- et diglycérides","note":"Émulsifiant anti-éclaboussures pour huile de friture.","detail":{"risks":"Huile de soja délibérément traitée thermiquement et estérifiée pour que la margarine de friture dore uniformément au lieu d'éclabousser. Réévaluée par l'EFSA avec une marge de sécurité confortable pour un usage typique.","benefits":"","interestingFact":"","research":""}},"e481":{"name":"Stéaroyl-2-lactylate de sodium","note":"Émulsifiant pour la boulangerie.","detail":{"risks":"Un hybride d'acide stéarique et d'acide lactique qui renforce le réseau de gluten — la raison pour laquelle le pain de mie tranché reprend sa forme lorsqu'on le presse. Digéré en gras ordinaire et en lactate.","benefits":"","interestingFact":"","research":""}},"e482":{"name":"Stéaroyl-2-lactylate de calcium","note":"Émulsifiant pour la boulangerie.","detail":{"risks":"Le jumeau calcique de l'E481, effectuant le même travail de renforcement de la pâte dans les pains et les préparations pour pancakes.","benefits":"","interestingFact":"","research":""}},"e491":{"name":"Monostéarate de sorbitane","note":"Émulsifiant, acceptable aux doses typiques.","detail":{"risks":"Du sorbitol (un polyol) lié à de la matière grasse stéarique — surnommé « cire synthétique ». Il aide la levure sèche à s'hydrater uniformément et maintient la stabilité des garnitures fouettées ; l'EFSA a réaffirmé une marge de sécurité confortable en 2017.","benefits":"","interestingFact":"","research":""}},"e492":{"name":"Tristéarate de sorbitane","note":"Inhibiteur du blanchiment du chocolat.","detail":{"risks":"Un émulsifiant de sorbitane qui ralentit le « blanchiment » grisâtre du chocolat — ces cristaux de beurre de cacao qui migrent à la surface avec le temps. Même famille et même réévaluation de sécurité que l'E491.","benefits":"","interestingFact":"","research":""}},"e493":{"name":"Monolaurate de sorbitane","note":"Émulsifiant.","detail":{"risks":"Le membre à base d'acide laurique de la famille des sorbitanes, utilisé dans les garnitures et les glaçages. Décomposé en sorbitol et en gras pendant la digestion.","benefits":"","interestingFact":"","research":""}},"e495":{"name":"Monopalmitate de sorbitane","note":"Émulsifiant.","detail":{"risks":"Le sorbitane d'acide palmitique, principalement un agent de foisonnement. Mêmes modalités de digestion que ses frères de la famille E49x.","benefits":"","interestingFact":"","research":""}},"e500":{"name":"Carbonates de sodium","note":"Bicarbonate de soude.","detail":{"risks":"Le bicarbonate de soude et ses cousins — la source de gaz dans la plupart des poudres à lever. C'est aussi ce qui donne aux bretzels et aux nouilles ramen leur texture alcaline si caractéristique.","benefits":"","interestingFact":"","research":""}},"e501":{"name":"Carbonates de potassium","note":"Poudre à lever.","detail":{"risks":"Le cousin au potassium du bicarbonate — historiquement la « cendre de perle », lixiviée à partir de cendres de bois, la poudre à lever du pain d'épices d'avant la levure chimique.","benefits":"","interestingFact":"","research":""}},"e503":{"name":"Carbonates d'ammonium","note":"Poudre à lever traditionnelle.","detail":{"risks":"L'« ammoniac du boulanger », l'agent levant d'autrefois dans les anciennes recettes de biscuits européens. Il dégage une forte odeur d'ammoniac au four, mais toutes les traces s'évaporent à la cuisson, laissant des biscuits particulièrement croustillants.","benefits":"","interestingFact":"","research":""}},"e504":{"name":"Carbonates de magnésium","note":"Antiagglomérant (aussi la magnésie d'escalade).","detail":{"risks":"La poudre blanche dont les gymnastes et les grimpeurs s'enduisent les mains, et qui empêche le sel de table de s'agglomérer. L'acide gastrique la transforme en simple magnésium dissous.","benefits":"","interestingFact":"","research":""}},"e507":{"name":"Acide chlorhydrique","note":"Acide de transformation, neutralisé dans le produit.","detail":{"risks":"Cela peut sembler alarmant, mais votre estomac produit chaque jour le même acide à une concentration plus élevée. Dans la transformation alimentaire, il est neutralisé avant la fin de la fabrication du produit.","benefits":"","interestingFact":"","research":""}},"e508":{"name":"Chlorure de potassium","note":"Minéral substitut du sel.","detail":{"risks":"Le substitut de sel pauvre en sodium classique — du potassium au lieu du sodium, avec une pointe légèrement métallique. Pour la plupart des gens, cet apport en potassium est un plus.","benefits":"","interestingFact":"","research":""}},"e509":{"name":"Chlorure de calcium","note":"Agent d'affermissement (légumes en conserve, fabrication du fromage).","detail":{"risks":"Un sel de calcium qui réticule les pectines végétales, maintenant la fermeté des tomates en conserve et des cornichons. Les fromagers en ajoutent au lait pour favoriser le caillage. C'est aussi le « liquide » de nombreux dégivrants — tout est une question de concentration.","benefits":"","interestingFact":"","research":""}},"e511":{"name":"Chlorure de magnésium","note":"Agent d'affermissement (aussi le nigari, coagulant du tofu).","detail":{"risks":"Du magnésium d'eau de mer — sous forme de « nigari », le coagulant japonais traditionnel du tofu qui transforme le lait de soja en caillé. Une source de magnésium alimentaire.","benefits":"","interestingFact":"","research":""}},"e513":{"name":"Acide sulfurique","note":"Acide de transformation, neutralisé dans le produit.","detail":{"risks":"Utilisé uniquement lors de la transformation (pour ajuster l'acidité de l'eau de brassage, par exemple) et entièrement neutralisé sous forme de sels de sulfate avant d'arriver dans le commerce.","benefits":"","interestingFact":"","research":""}},"e514":{"name":"Sulfates de sodium","note":"Correcteur d'acidité.","detail":{"risks":"Un sel minéral neutre — le sel de Glauber pour les apothicaires du 18e siècle, qui le prescrivaient comme laxatif, ce qu'il reste à fortes doses.","benefits":"","interestingFact":"","research":""}},"e516":{"name":"Sulfate de calcium","note":"Gypse — coagulant pour tofu, traitement des farines.","detail":{"risks":"Du gypse de qualité alimentaire (le minéral des plaques de plâtre, purifié). C'est le coagulant classique du tofu chinois et un nutriment pour levures en boulangerie, apportant au passage du calcium assimilable.","benefits":"","interestingFact":"","research":""}},"e524":{"name":"Hydroxydes de sodium","note":"Soude caustique — agent de transformation, ayant totalement réagi dans le produit.","detail":{"risks":"Caustique dans la bouteille, inoffensif dans l'assiette : les bretzels doivent leur croûte acajou à un bain de soude, totalement neutralisé par la cuisson.","benefits":"","interestingFact":"","research":""}},"e526":{"name":"Hydroxyde de calcium","note":"Chaux éteinte, auxiliaire de technologie.","detail":{"risks":"La chaux éteinte — le « cal » de la nixtamalisation mexicaine, qui ramollit le maïs pour les tortillas depuis 3 500 ans et libère sa niacine. Totalement neutralisé dans l'aliment final.","benefits":"","interestingFact":"","research":""}},"e527":{"name":"Hydroxyde d'ammonium","note":"Alcali de transformation.","detail":{"risks":"Une solution d'ammoniac utilisée pour ajuster l'acidité durant la transformation (notamment du cacao). Elle réagit ou s'évapore ; l'ammonium restant intègre le métabolisme normal de l'azote.","benefits":"","interestingFact":"","research":""}},"e529":{"name":"Oxyde de calcium","note":"Chaux vive, auxiliaire de technologie.","detail":{"risks":"La chaux vive — elle s'éteint en hydroxyde de calcium dès qu'elle entre en contact avec l'humidité, accomplissant le même rôle que l'E526 pour finir sous forme de simple calcium.","benefits":"","interestingFact":"","research":""}},"e530":{"name":"Oxyde de magnésium","note":"Minéral antiagglomérant.","detail":{"risks":"Le même oxyde de magnésium que celui vendu comme complément et antacide, servant ici à préserver la fluidité de la poudre de cacao.","benefits":"","interestingFact":"","research":""}},"e535":{"name":"Ferrocyanure de sodium","note":"Antiagglomérant dans le sel.","detail":{"risks":"Malgré un nom effrayant, le cyanure est si fortement lié au fer qu'il traverse l'organisme sans être absorbé — c'est ce qui empêche le sel de table de s'agglomérer par temps humide.","benefits":"","interestingFact":"","research":""}},"e536":{"name":"Ferrocyanure de potassium","note":"Antiagglomérant dans le sel.","detail":{"risks":"La forme potassique de l'E535, avec la même chimie liée au fer : le groupe cyanure ne peut pas être libéré dans l'organisme, et l'EFSA a réaffirmé son innocuité en 2018.","benefits":"","interestingFact":"","research":""}},"e538":{"name":"Ferrocyanure de calcium","note":"Antiagglomérant dans le sel.","detail":{"risks":"Le plus rare des trois sels antiagglomérants de ferrocyanure, présentant une chimie liée identique et ayant fait l'objet de la même évaluation par l'EFSA.","benefits":"","interestingFact":"","research":""}},"e541":{"name":"Phosphate d'aluminium et de sodium","note":"Poudre à lever à base d'aluminium.","detail":{"risks":"Un acide de cuisson à action lente dont l'aluminium contribue à l'exposition alimentaire totale — l'EFSA a durci les règles sur les additifs à base d'aluminium en 2012 et il a largement disparu des recettes dans l'EU.","benefits":"","interestingFact":"","research":""}},"e551":{"name":"Dioxyde de silicium","note":"Antiagglomérant ; teneur en nanoparticules sous examen dans l'EU.","detail":{"risks":"Du sable purifié, sous forme de poudre si fine qu'elle enrobe les particules et préserve la fluidité des mélanges d'épices et des soupes instantanées. Chimiquement inerte ; la question en suspens étudiée par l'EFSA est de savoir si sa fraction nanométrique peut s'accumuler.","benefits":"","interestingFact":"","research":""}},"e552":{"name":"Silicate de calcium","note":"Minéral antiagglomérant.","detail":{"risks":"Un minéral de craie et de silice qui absorbe plusieurs fois son poids en humidité, maintenant la fluidité des poudres. Pratiquement non absorbé.","benefits":"","interestingFact":"","research":""}},"e553b":{"name":"Talc","note":"Minéral antiagglomérant (qualité alimentaire, sans amiante).","detail":{"risks":"Le minéral le plus tendre de la Terre, servant à polir les grains de riz et à poudrer les chewing-gums. La qualité alimentaire est certifiée sans amiante ; il traverse le corps sans être digéré.","benefits":"","interestingFact":"","research":""}},"e554":{"name":"Aluminosilicate de sodium","note":"Antiagglomérant à base d'aluminium.","detail":{"risks":"Une argile antiagglomérante dont la teneur en aluminium compte dans la limite hebdomadaire stricte fixée par l'EFSA — la raison pour laquelle les régulateurs de l'EU ont restreint ce groupe en 2014.","benefits":"","interestingFact":"","research":""}},"e555":{"name":"Aluminosilicate de potassium","note":"Support à base d'aluminium (couleurs nacrées).","detail":{"risks":"Du mica naturel — le reflet sous les décorations de gâteaux nacrées. Signalé pour la même raison d'accumulation d'aluminium que ses équivalents.","benefits":"","interestingFact":"","research":""}},"e558":{"name":"Bentonite","note":"Argile utilisée pour clarifier le vin et les jus.","detail":{"risks":"Une argile volcanique qui gonfle dans l'eau et capte les protéines responsables du trouble — la plupart des vins blancs que vous avez bus ont été clarifiés avec elle, puis filtrés.","benefits":"","interestingFact":"","research":""}},"e559":{"name":"Kaolin","note":"Argile antiagglomérante.","detail":{"risks":"L'argile de Chine — le minéral de la porcelaine — parfois utilisée comme antiagglomérant. Inerte et non absorbée.","benefits":"","interestingFact":"","research":""}},"e570":{"name":"Acides gras","note":"Acides gras alimentaires ordinaires.","detail":{"risks":"L'acide stéarique et ses dérivés — les mêmes acides gras que ceux que votre corps tire de n'importe quelle matière grasse, utilisés comme agents d'enrobage et antiagglomérants.","benefits":"","interestingFact":"","research":""}},"e575":{"name":"Glucono-delta-lactone","note":"Acide à libération lente (tofu, charcuteries).","detail":{"risks":"Un sucre oxydé qui devient lentement acide au contact de l'eau — parfait pour le tofu soyeux, où la baisse progressive du pH transforme le lait de soja en un gel lisse.","benefits":"","interestingFact":"","research":""}},"e576":{"name":"Gluconate de sodium","note":"Sel minéral d'acide gluconique.","detail":{"risks":"Du glucose oxydé et lié au sodium — un vecteur minéral et stabilisant métabolisé comme du sucre.","benefits":"","interestingFact":"","research":""}},"e577":{"name":"Gluconate de potassium","note":"Sel minéral d'acide gluconique.","detail":{"risks":"La forme potassique du gluconate, suffisamment douce pour que les pharmacies la vendent comme complément de potassium.","benefits":"","interestingFact":"","research":""}},"e578":{"name":"Gluconate de calcium","note":"Sel de calcium, agent d'affermissement.","detail":{"risks":"Du calcium sur un support d'acide glucorique — le même composé administré à l'hôpital par voie intraveineuse en cas de manque de calcium. Dans l'alimentation, il raffermit les fruits et légumes.","benefits":"","interestingFact":"","research":""}},"e579":{"name":"Gluconate ferreux","note":"Sel de fer — noircit les olives.","detail":{"risks":"Un complément en fer jouant un rôle de colorant : les olives « noires » en conserve sont généralement des olives vertes oxydées en noir et fixées avec ce sel de fer.","benefits":"","interestingFact":"","research":""}},"e585":{"name":"Lactate ferreux","note":"Sel de fer, colorant pour olives.","detail":{"risks":"Du fer véhiculé par le lactate, accomplissant le même travail de noircissement des olives que l'E579 et utilisé pour enrichir les aliments en fer.","benefits":"","interestingFact":"","research":""}},"e586":{"name":"4-Hexylrésorcinol","note":"Agent anti-brunissement pour les crevettes.","detail":{"risks":"Empêche la carapace des crevettes de développer des taches noires après la capture en bloquant la même enzyme qui brunit les pommes coupées. Également un antiseptique pour pastilles pour la gorge.","benefits":"","interestingFact":"","research":""}},"e620":{"name":"Acide glutamique","note":"Exhausteur d'umami ; réactions de sensibilité chez certaines personnes.","detail":{"risks":"La forme libre de l'acide aminé le plus abondant dans votre alimentation — le parmesan contient 1,2 % de glutamate pur. En tant qu'additif, il concentre l'umami ; les débats sur la sensibilité et la surconsommation reflètent ceux du glutamate monosodique (E621).","benefits":"","interestingFact":"","research":""}},"e621":{"name":"Glutamate monosodique","note":"Exhausteur de goût ; réactions de sensibilité chez certaines personnes.","detail":{"risks":"La forme pure de l'umami, identifiée en 1908 à partir du bouillon d'algues kombu. Le glutamate lui-même est présent dans le parmesan, les tomates et le lait maternel ; la panique du « syndrome du restaurant chinois » de 1968 a largement échoué lors des tests contrôlés, bien qu'une minorité réagisse aux doses élevées. L'EFSA a fixé une limite d'apport formelle en 2017 — principalement dépassée par les régimes riches en snacks ultratransformés. Son vrai problème nutritionnel : il rend les aliments ultratransformés très faciles à surconsommer.","benefits":"","interestingFact":"","research":""}},"e622":{"name":"Glutamate monopotassique","note":"Exhausteur de goût au glutamate.","detail":{"risks":"Du glutamate monosodique où le potassium remplace le sodium, utilisé dans les recettes pauvres en sodium. Mécanisme umami identique et même limite d'apport en glutamate fixée par l'EFSA.","benefits":"","interestingFact":"","research":""}},"e627":{"name":"Guanylate disodique","note":"Exhausteur de goût, souvent associé au glutamate monosodique.","detail":{"risks":"Un nucléotide qui multiplie l'umami — combiné au glutamate monosodique, son goût est jusqu'à 30× plus puissant que séparément, ce qui explique pourquoi ils vont de pair sur les étiquettes. Dérivé de la levure ou du poisson ; il est conseillé aux personnes souffrant de goutte de limiter les additifs riches en purines comme celui-ci.","benefits":"","interestingFact":"","research":""}},"e628":{"name":"Guanylate dipotassique","note":"Exhausteur de goût nucléotidique.","detail":{"risks":"La forme potassique du guanylate (E627), amplifiant l'umami dans les produits pauvres en sodium. Même origine de levure et même remarque sur les purines pour les personnes sujettes à la goutte.","benefits":"","interestingFact":"","research":""}},"e631":{"name":"Inosinate disodique","note":"Exhausteur de goût, souvent associé au glutamate monosodique.","detail":{"risks":"Le nucléotide umami des flocons de bonite séchée (la base du dashi japonais), aujourd'hui produit par fermentation. Même synergie avec le glutamate monosodique et mêmes remarques sur les purines que l'E627.","benefits":"","interestingFact":"","research":""}},"e635":{"name":"5'-ribonucléotide disodique","note":"Mélange E627 + E631 ; booster d'umami.","detail":{"risks":"Un mélange 50/50 de guanylate et d'inosinate — une seule ligne sur l'étiquette fournissant les deux nucléotides umami. Sa présence signale presque toujours la proximité du glutamate monosodique (ou d'un extrait riche en glutamate), car il agit peu lorsqu'il est seul.","benefits":"","interestingFact":"","research":""}},"e640":{"name":"Glycine","note":"L'acide aminé le plus simple, douceur légère.","detail":{"risks":"Le plus petit acide aminé — un tiers de la protéine de collagène est constitué de glycine. En tant qu'additif, il adoucit les notes amères et apporte une légère touche sucrée.","benefits":"","interestingFact":"","research":""}},"e650":{"name":"Acétate de zinc","note":"Sel de zinc (chewing-gum).","detail":{"risks":"Du zinc lié à l'acide acétique, principalement dans les chewing-gums « haleine fraîche » où le zinc neutralise les composés soufrés. Le même sel est utilisé dans les pastilles contre le rhume.","benefits":"","interestingFact":"","research":""}},"e900":{"name":"Diméthylpolysiloxane","note":"Agent anti-moussant en silicone (huile de friture).","detail":{"risks":"Un silicone de qualité alimentaire qui empêche l'huile de friture de mousser et de déborder — la raison pour laquelle les friteuses de restauration rapide ne débordent pas. Totalement inerte et non absorbé ; c'est aussi le composant principal du Silly Putty.","benefits":"","interestingFact":"","research":""}},"e901":{"name":"Cire d'abeille","note":"Cire d'enrobage naturelle.","detail":{"risks":"La même cire avec laquelle les abeilles construisent les alvéoles, polie sur les bonbons gélifiés et les agrumes pour la brillance. Indigestible — elle traverse directement le système digestif.","benefits":"","interestingFact":"","research":""}},"e902":{"name":"Cire de candelilla","note":"Cire d'enrobage végétale.","detail":{"risks":"Une cire grattée sur un arbuste du désert mexicain qui se protège contre la sécheresse — et qui enrobe désormais vos oursons en gelée. Indigestible et inerte.","benefits":"","interestingFact":"","research":""}},"e903":{"name":"Cire de carnauba","note":"Cire d'enrobage issue de feuilles de palmier.","detail":{"risks":"Issue de feuilles de palmier brésilien — la cire naturelle la plus dure connue, faisant briller aussi bien les M&M’s que les voitures de sport.","benefits":"","interestingFact":"","research":""}},"e904":{"name":"Gomme-laque","note":"Glaçage à la résine d'insecte.","detail":{"risks":"Sécrétée par la cochenille lacque sur les arbres thaïlandais et indiens, puis purifiée — la couche brillante sur les lentilles en chocolat et les pommes, et la même résine que dans le vernis au tampon des meubles. Non végétarien.","benefits":"","interestingFact":"","research":""}},"e905":{"name":"Cire microcristalline","note":"Cire d'enrobage dérivée du pétrole.","detail":{"risks":"Une cire de pétrole très raffinée enrobant les chewing-gums et les bonbons. Trop volumineuse pour être absorbée, elle traverse le corps — la seule exigence de l'EFSA concerne le contrôle de sa pureté.","benefits":"","interestingFact":"","research":""}},"e914":{"name":"Cire de polyéthylène oxydée","note":"Cire synthétique d'enrobage des agrumes.","detail":{"risks":"Une cire synthétique pulvérisée sur l'écorce des agrumes pour ralentir la perte d'humidité entre le verger et l'étal. Elle reste sur la peau ; lavez le fruit avant d'en prélever le zeste.","benefits":"","interestingFact":"","research":""}},"e920":{"name":"L-Cystéine","note":"Agent de traitement de la pâte issu de fermentation.","detail":{"risks":"Un acide aminé qui détend le gluten pour que les pétrins industriels puissent l'étirer rapidement. Historiquement extrait de plumes et de cheveux humains (sources interdites dans l'EU depuis 2001 — il est désormais fermenté à partir de sucre), un fait qui entretient sa réputation pittoresque.","benefits":"","interestingFact":"","research":""}},"e927b":{"name":"Carbamide","note":"Texturant pour chewing-gum.","detail":{"risks":"De l'urée — une molécule que votre corps produit constamment lors du métabolisme des protéines — qui ramollit les chewing-gums sans sucre. Banale aux doses milligrammiques impliquées.","benefits":"","interestingFact":"","research":""}},"e938":{"name":"Argon","note":"Gaz d'emballage inerte.","detail":{"risks":"Un gaz noble présent dans l'air (1 % de chaque inspiration) qui ne réagit avec rien — injecté dans les emballages pour en chasser l'oxygène.","benefits":"","interestingFact":"","research":""}},"e939":{"name":"Hélium","note":"Gaz d'emballage inerte.","detail":{"risks":"Le gaz des ballons, totalement inerte, parfois utilisé pour isoler les aliments dans les emballages. Il s'échappe dès que vous ouvrez le paquet.","benefits":"","interestingFact":"","research":""}},"e941":{"name":"Azote","note":"Gaz d'emballage — 78 % de l'air que vous respirez.","detail":{"risks":"Le gaz qui remplit l'espace « vide » des paquets de chips n'est pas une arnaque — c'est de l'azote qui protège les chips de l'oxygène et de l'écrasement. C'est aussi ce qui rend le café nitro si onctueux.","benefits":"","interestingFact":"","research":""}},"e942":{"name":"Protoxyde d'azote","note":"Propulseur pour crème fouettée (gaz hilarant).","detail":{"risks":"Le propulseur des cartouches de chantilly. Il se dissout dans la crème sous pression et décuple son volume à la sortie — la trace que vous ingérez disparaît en quelques minutes.","benefits":"","interestingFact":"","research":""}},"e948":{"name":"Oxygène","note":"Gaz d'emballage.","detail":{"risks":"De l'oxygène pur, parfois ajouté aux barquettes de viande rouge pour conserver sa couleur éclatante à la surface. Vous en inhalez bien plus à chaque respiration.","benefits":"","interestingFact":"","research":""}},"e949":{"name":"Hydrogène","note":"Gaz d'emballage.","detail":{"risks":"Le gaz le plus léger, rarement utilisé comme atmosphère d'emballage. Inerte dans les aliments et disparu depuis longtemps au moment où vous mangez.","benefits":"","interestingFact":"","research":""}},"e999":{"name":"Extrait de quillaia","note":"Agent moussant à base de bois de Panama (mousse de root beer).","detail":{"risks":"Extrait de l'arbre chilien bois de Panama, dont les saponines naturelles créent le col de mousse de la root beer. Le même extrait est utilisé comme adjuvant de vaccin — aux doses alimentaires, il ne fait que des bulles.","benefits":"","interestingFact":"","research":""}},"e950":{"name":"Acésulfame K","note":"Édulcorant artificiel ; effets à long terme débattus.","detail":{"risks":"200× plus sucré que le sucre, zéro calorie, non métabolisé du tout — il quitte votre corps intact en moins de 24 heures. L'épidémiologie à long terme (y compris les recommandations de la WHO en 2023 contre les édulcorants pour le contrôle du poids) maintient le débat ouvert.","benefits":"","interestingFact":"","research":""}},"e951":{"name":"Aspartame","note":"Classé 2B par l'IARC (peut-être cancérogène, 2023) ; des limites d'apport s'appliquent.","detail":{"risks":"Deux acides aminés reliés ensemble, 200× plus sucrés que le sucre. En 2023, l'IARC l'a classé « peut-être cancérogène » (la même catégorie 2B que l'aloe vera et les légumes au vinaigre) tandis que le comité d'experts sur les additifs alimentaires de la WHO a maintenu sa limite d'apport — environ 12 canettes de soda light par jour pour un adulte. Les personnes atteintes de la maladie génétique PCU doivent l'éviter totalement ; c'est le but de l'avertissement « contient une source de phénylalanine ».","benefits":"","interestingFact":"","research":""}},"e952":{"name":"Cyclamates","note":"Édulcorant interdit aux US, doses restreintes dans l'EU.","detail":{"risks":"Découvert en 1937 par un étudiant qui avait posé sa cigarette sur une poudre de laboratoire et en a senti la saveur sucrée. Interdit aux US depuis 1970 en raison de découvertes (contestées par la suite) sur des tumeurs chez le rat ; l'EU l'autorise sous des limites strictes.","benefits":"","interestingFact":"","research":""}},"e953":{"name":"Isomalt","note":"Polyol ; laxatif à fortes doses.","detail":{"risks":"Le chouchou des sculpteurs sur sucre — il fond avec la clarté du verre sans caraméliser, c'est pourquoi les pièces montées des émissions de pâtisserie sont généralement en isomalt. Les précautions digestives habituelles pour les polyols s'appliquent.","benefits":"","interestingFact":"","research":""}},"e954":{"name":"Saccharine","note":"Édulcorant artificiel à l'histoire débattue.","detail":{"risks":"Le plus ancien édulcorant artificiel (1879, découvert par un chimiste qui ne s'était pas lavé les mains avant de dîner). A porté un avertissement de risque de cancer aux US pendant 20 ans jusqu'à ce qu'il soit démontré que le mécanisme sur la vessie du rat ne s'appliquait pas à l'homme — retiré de la liste en 2000, mais son ombre plane toujours.","benefits":"","interestingFact":"","research":""}},"e955":{"name":"Sucralose","note":"Édulcorant artificiel ; débats sur la cuisson et le microbiote.","detail":{"risks":"Du sucre dans lequel trois atomes de chlore ont été substitués — 600× plus sucré et en grande partie non absorbé. Débats actuels : il peut se décomposer en composés douteux à des températures de cuisson élevées, et les études divergent quant à ses effets sur le microbiote intestinal.","benefits":"","interestingFact":"","research":""}},"e957":{"name":"Thaumatine","note":"Protéine sucrée issue d'un fruit africain.","detail":{"risks":"Une protéine issue du fruit du katemfe d'Afrique de l'Ouest — la substance naturelle la plus sucrée connue, environ 2 000× plus sucrée que le sucre à poids égal. Digérée comme n'importe quelle autre protéine.","benefits":"","interestingFact":"","research":""}},"e959":{"name":"Néohésperidine DC","note":"Édulcorant dérivé d'agrumes.","detail":{"risks":"Fabriqué à partir de composés de l'écorce d'orange amère, 1 500× plus sucré que le sucre avec un arrière-goût mentholé ; également utilisé pour masquer l'amertume dans les médicaments.","benefits":"","interestingFact":"","research":""}},"e960":{"name":"Glycosides de stéviol","note":"Édulcorant dérivé de la stévia.","detail":{"risks":"Extrait des feuilles de stévia, utilisé par le peuple Guaraní au Paraguay depuis des siècles. 250–300× plus sucré que le sucre avec zéro calorie ; vos bactéries intestinales le décomposent et il est excrété. La légère note de réglisse en arrière-goût en est la contrepartie.","benefits":"","interestingFact":"","research":""}},"e961":{"name":"Néotame","note":"Dérivé de l'aspartame, 8000× plus sucré que le sucre.","detail":{"risks":"Un aspartame réingéniéré pour être environ 40× plus puissant et stable à la cuisson. Les doses sont microscopiques et, contrairement à l'aspartame, il libère trop peu de phénylalanine pour nécessiter un avertissement concernant la PCU ; les données à long terme sont tout simplement plus rares.","benefits":"","interestingFact":"","research":""}},"e962":{"name":"Sel d'aspartame-acésulfame","note":"Édulcorant combiné ; voir les notes sur l'aspartame.","detail":{"risks":"De l'aspartame et de l'acésulfame K cristallisés ensemble en une seule molécule qui se sépare à nouveau dans votre bouche — toutes les remarques valables pour chacun s'appliquent, y compris l'avertissement concernant la PCU.","benefits":"","interestingFact":"","research":""}},"e965":{"name":"Maltitol","note":"Polyol ; laxatif à forte dose.","detail":{"risks":"Le substitut du sucre incontournable dans le chocolat « sans sucres ajoutés » — 90 % du pouvoir sucrant du sucre avec deux fois moins de calories. C'est aussi le polyol le plus réputé pour les protestations digestives au-delà de ~20 g, d'où les avertissements sur les bonbons sans sucre.","benefits":"","interestingFact":"","research":""}},"e966":{"name":"Lactitol","note":"Polyol dérivé du lait ; laxatif à forte dose.","detail":{"risks":"Un polyol fabriqué à partir de sucre de lait, légèrement sucré et principalement fermenté par les bactéries intestinales — aux doses pharmacologiques, la même molécule est littéralement vendue comme laxatif.","benefits":"","interestingFact":"","research":""}},"e967":{"name":"Xylitol","note":"Polyol ; laxatif à forte dose.","detail":{"risks":"Un polyol issu de l'écorce de bouleau que les bactéries buccales ne peuvent pas fermenter — mâcher du chewing-gum au xylitol réduit de façon mesurable les caries, un rare additif au bienfait prouvé. Deux mises en garde : laxatif au-delà de ~30 g, et extrêmement toxique pour les chiens.","benefits":"","interestingFact":"","research":""}},"e968":{"name":"Érythritol","note":"Polyol ; une étude de 2023 a ouvert un débat cardiovasculaire.","detail":{"risks":"Le polyol le plus doux — 90 % est absorbé avant d'atteindre le côlon, donc presque aucun effet digestif, et zéro calorie. Une étude de 2023 dans Nature Medicine a associé un taux sanguin élevé d'érythritol à un risque de caillots ; le fait que l'érythritol alimentaire en soit la cause fait actuellement l'objet de recherches actives.","benefits":"","interestingFact":"","research":""}},"e1103":{"name":"Invertase","note":"Enzyme qui liquéfie le cœur des bonbons.","detail":{"risks":"L'enzyme (issue de la levure) qui transforme le fondant ferme en liquide sur plusieurs semaines — c'est ainsi que les cerises enrobées de chocolat obtiennent leur cœur coulant après avoir été fourrées d'une pâte solide.","benefits":"","interestingFact":"","research":""}},"e1105":{"name":"Lysozyme","note":"Enzyme conservatrice du blanc d'œuf (fromage, vin).","detail":{"risks":"Une enzyme antibactérienne tirée du blanc d'œuf — la même que celle présente dans vos larmes et votre salive. Les consommateurs allergiques aux œufs doivent savoir qu'elle se cache dans certains fromages à pâte dure et certains vins.","benefits":"","interestingFact":"","research":""}},"e1200":{"name":"Polydextrose","note":"Fibre soluble synthétique.","detail":{"risks":"Du glucose lié selon des motifs que vos enzymes ne peuvent pas découper, de sorte qu'il se comporte comme une fibre soluble — apportant de la texture aux aliments « allégés » à raison de 1 kcal/g au lieu des 4 du sucre.","benefits":"","interestingFact":"","research":""}},"e1201":{"name":"Polyvinylpyrrolidone","note":"Clarifiant et liant pour comprimés.","detail":{"risks":"Un polymère qui capture les polyphénols susceptibles de troubler la bière et les jus, puis qui est éliminé avec eux par filtration. Les éventuelles traces restantes traversent l'organisme sans être absorbées.","benefits":"","interestingFact":"","research":""}},"e1400":{"name":"Dextrines","note":"Épaississant d'amidon torréfié.","detail":{"risks":"De l'amidon légèrement décomposé par torréfaction — la même chimie que celle qui dore la croûte d'une baguette. Digéré exactement comme de l'amidon.","benefits":"","interestingFact":"","research":""}},"e1404":{"name":"Amidon oxydé","note":"Amidon modifié ; digéré comme de l'amidon.","detail":{"risks":"Un amidon traité pour épaissir à une viscosité plus faible pour les crèmes et les pâtes à frire. « Modifié » signifie ajusté physiquement ou chimiquement — et non génétiquement modifié — et il se digère comme de l'amidon ordinaire.","benefits":"","interestingFact":"","research":""}},"e1410":{"name":"Phosphate de monoamidon","note":"Amidon modifié ; digéré comme de l'amidon.","detail":{"risks":"De l'amidon doté d'ancrages phosphate qui résistent à la chaleur et à l'acidité, afin que les sauces en conserve restent onctueuses. Digéré comme de l'amidon.","benefits":"","interestingFact":"","research":""}},"e1412":{"name":"Phosphate de diamidon","note":"Amidon modifié ; digéré comme de l'amidon.","detail":{"risks":"De l'amidon réticulé par des ponts phosphate pour résister à l'agitation et à la chaleur — la base des crèmes desserts instantanées. Digéré comme de l'amidon.","benefits":"","interestingFact":"","research":""}},"e1414":{"name":"Phosphate de diamidon acétylé","note":"Amidon modifié ; digéré comme de l'amidon.","detail":{"risks":"Un amidon réticulé additionné de groupes acétyle pour la stabilité à la congélation et à la décongélation — ce qui explique pourquoi les plats cuisinés surgelés ne rendent pas d'eau lorsqu'ils sont réchauffés. Digéré comme de l'amidon.","benefits":"","interestingFact":"","research":""}},"e1420":{"name":"Amidon acétylé","note":"Amidon modifié ; digéré comme de l'amidon.","detail":{"risks":"De l'amidon doté de groupes acétyle dérivés du vinaigre, résistant à la rétrogradation (le processus de rassissement). Digéré comme de l'amidon.","benefits":"","interestingFact":"","research":""}},"e1422":{"name":"Adipate de diamidon acétylé","note":"Amidon modifié ; digéré comme de l'amidon.","detail":{"risks":"« Amidon modifié » ne signifie pas génétiquement modifié — il s'agit d'amidon de maïs ou de pomme de terre ajusté chimiquement pour que les sauces résistent à la congélation et au réchauffage sans devenir aqueuses. Votre corps le digère comme de l'amidon ordinaire.","benefits":"","interestingFact":"","research":""}},"e1440":{"name":"Amidon hydroxypropylé","note":"Amidon modifié, généralement bien toléré.","detail":{"risks":"De l'amidon doté de groupes latéraux hydrophiles pour un épaississement fluide à basse température. Largement digéré comme de l'amidon ; la fraction modifiée passe comme une fibre.","benefits":"","interestingFact":"","research":""}},"e1442":{"name":"Phosphate de diamidon hydroxypropylé","note":"Amidon modifié, généralement bien toléré.","detail":{"risks":"Le plus robuste des amidons modifiés — réticulé et substitué, il épaissit aussi bien à l'appertisation qu'à la congélation et au réchauffage. Principalement digéré comme de l'amidon.","benefits":"","interestingFact":"","research":""}},"e1450":{"name":"Octényl succinate de sodium d'amidon","note":"Émulsifiant à base d'amidon (également dans les vitamines).","detail":{"risks":"De l'amidon doté d'une queue lipophile lui permettant d'émulsionner — le support qui maintient les arômes en poudre et les vitamines du lait infantile dispersés de façon homogène.","benefits":"","interestingFact":"","research":""}},"e1451":{"name":"Amidon acétylé oxydé","note":"Amidon modifié ; digéré comme de l'amidon.","detail":{"risks":"Un amidon doublement traité combinant la clarté de l'oxydation et la stabilité de l'acétylation. Sur le plan digestif, cela reste simplement de l'amidon.","benefits":"","interestingFact":"","research":""}},"e1505":{"name":"Citrate de triéthyle","note":"Support d'arôme citrate et stabilisant de mousse.","detail":{"risks":"De l'acide citrique doté de trois groupes éthanol — il stabilise les blancs d'œufs en neige dans les œufs liquides en brique et transporte les arômes. Séparé en citrate et traces d'alcool pendant la digestion.","benefits":"","interestingFact":"","research":""}},"e1518":{"name":"Triacétine","note":"Support d'arôme à base de glycérol.","detail":{"risks":"Du glycérol portant trois groupes d'acide acétique, dissolvant les arômes dans les chewing-gums et les bonbons. Digéré en glycérol et en acétate, deux métabolites courants.","benefits":"","interestingFact":"","research":""}},"e1520":{"name":"Propylène glycol","note":"Support d'arôme ; sûr aux doses alimentaires.","detail":{"risks":"Le solvant qui transporte la plupart des arômes alimentaires liquides. Métabolisé en acide lactique ; la limite de l'EFSA est généreuse par rapport à l'exposition alimentaire. Sa mauvaise réputation provient principalement de son utilisation dans les cigarettes électroniques et les formules antigel — aux doses alimentaires, il est sans histoire.","benefits":"","interestingFact":"","research":""}}}`),n={methylparaben:{note:`Short-chain paraben; SCCS finds it safe at ≤0.4%, but it is a documented weak endocrine mimic.`},ethylparaben:{note:`Short-chain paraben; permitted in the EU with concentration limits.`},propylparaben:{note:`Longer-chain paraben with stronger endocrine-activity evidence; EU-restricted concentration.`},butylparaben:{note:`Longer-chain paraben with the strongest endocrine-activity evidence; EU-restricted.`},isobutylparaben:{note:`Banned in EU cosmetics since 2014.`},paraben:{note:`Paraben-family preservative; endocrine-activity debate varies by chain length.`},formaldehyde:{note:`IARC Group 1 carcinogen; banned/heavily restricted in EU cosmetics.`},"dmdm hydantoin":{note:`Slowly releases formaldehyde; sensitization concern.`},"imidazolidinyl urea":{note:`Formaldehyde releaser; common contact-allergy trigger.`},"diazolidinyl urea":{note:`Formaldehyde releaser; common contact-allergy trigger.`},"quaternium-15":{note:`Strong formaldehyde releaser; banned in EU cosmetics since 2022.`},"2-bromo-2-nitropropane-1,3-diol":{note:`Formaldehyde releaser; can form nitrosamines with amines.`},methylisothiazolinone:{note:`Major contact allergen; banned in EU leave-on products.`},methylchloroisothiazolinone:{note:`Potent sensitizer; EU rinse-off only at strict limits.`},triclosan:{note:`Endocrine activity and antibiotic-resistance concerns; EU-restricted.`},phenoxyethanol:{note:`Widely used; SCCS finds it safe at ≤1%. Mild irritation potential.`},chlorphenesin:{note:`Preservative, occasional irritant.`},"benzyl alcohol":{note:`Preservative and declared fragrance allergen.`},"sodium benzoate":{note:`Mild, well-tolerated preservative at cosmetic doses.`},"potassium sorbate":{note:`Mild, well-tolerated preservative.`},"sodium lauryl sulfate":{note:`Effective cleanser; strips natural oils and irritates sensitive skin/scalp.`},"ammonium lauryl sulfate":{note:`SLS-class surfactant; similar irritation profile.`},"sodium laureth sulfate":{note:`Milder than SLS; trace 1,4-dioxane possible from manufacturing.`},"cocamidopropyl betaine":{note:`Mild surfactant; impurity-driven allergies occur.`},"cocamide dea":{note:`IARC 2B (possibly carcinogenic); banned in EU cosmetics.`},"cocamide mea":{note:`Nitrosamine formation possible with certain preservatives.`},triethanolamine:{note:`pH adjuster; nitrosamine formation concern in some formulas.`},"benzophenone-3":{note:`Endocrine-activity evidence; EU cut allowed concentration in 2022. Also reef-toxic.`},oxybenzone:{note:`Endocrine-activity evidence; EU-restricted. Also reef-toxic.`},"ethylhexyl methoxycinnamate":{note:`Estrogenic activity in studies; being phased down.`},octocrylene:{note:`Can degrade into benzophenone; photoallergy reports.`},homosalate:{note:`SCCS lowered safe concentration over endocrine questions.`},"butyl methoxydibenzoylmethane":{note:`Broadly used UVA filter; photostability is the main issue.`},"titanium dioxide":{note:`Safe on skin; avoid inhalable spray forms (nano).`},"zinc oxide":{note:`Mineral UV filter, well tolerated.`},"polyethylene terephthalate":{note:`Polymère synthétique solide — microplastique ajouté intentionnellement.`},polyethylene:{note:`Polymère classique pour microbilles ; restriction progressive dans l'EU.`},polypropylene:{note:`Polymère synthétique solide — microplastique ajouté intentionnellement.`},"polymethyl methacrylate":{note:`Microplastique acrylique utilisé pour la texture.`},"nylon-12":{note:`Poudre de microplastique polyamide.`},"nylon-6":{note:`Poudre de microplastique polyamide.`},"acrylates copolymer":{note:`Polymère filmogène ; considéré comme un microplastique lorsqu'il est solide.`},"acrylates crosspolymer":{note:`Polymère filmogène ; considéré comme un microplastique lorsqu'il est solide.`},cyclopentasiloxane:{note:`Restreint par l'EU dans les produits rincés (persistance environnementale).`},cyclotetrasiloxane:{note:`Classé reprotoxique et persistant par l'EU ; restreint.`},dimethicone:{note:`Agent filmogène inerte ; sûr, bien qu'il puisse s'accumuler sur les cheveux.`},amodimethicone:{note:`Silicone conditionneur, bien toléré.`},parfum:{note:`Mélange non divulgué — la source d'allergie cosmétique la plus fréquente.`},fragrance:{note:`Mélange non divulgué — la source d'allergie cosmétique la plus fréquente.`},limonene:{note:`Composant de parfum d'agrumes ; allergène déclaré dans l'EU lorsqu'il est oxydé.`},linalool:{note:`Composant de parfum floral ; allergène déclaré dans l'EU lorsqu'il est oxydé.`},citronellol:{note:`Allergène de parfum déclaré dans l'EU.`},geraniol:{note:`Allergène de parfum déclaré dans l'EU.`},eugenol:{note:`Allergène de parfum déclaré dans l'EU.`},coumarin:{note:`Allergène de parfum déclaré dans l'EU.`},"hexyl cinnamal":{note:`Allergène de parfum déclaré dans l'EU.`},"benzyl salicylate":{note:`Allergène de parfum déclaré dans l'EU.`},"alcohol denat":{note:`Asséchant pour la peau à forte concentration ; sans problème plus bas dans la liste.`},"propylene glycol":{note:`Humectant/solvant ; sensibilité occasionnelle.`},"peg-":{note:`Composé éthoxylé ; traces de 1,4-dioxane possibles issues de la fabrication.`},"p-phenylenediamine":{note:`Sensibilisant puissant — l'allergie classique aux teintures capillaires ; restreint par l'EU.`},resorcinol:{note:`Composant de teinture capillaire présentant des preuves d'activité thyroïdienne.`},hydroquinone:{note:`Agent éclaircissant pour la peau interdit dans les cosmétiques dans l'EU.`},toluene:{note:`Solvant neurotoxique ; interdit dans les cosmétiques dans l'EU.`},"salicylic acid":{note:`BHA exfoliant ; limites de concentration imposées par l'EU, à éviter chez les jeunes enfants.`},retinol:{note:`Actif anti-âge efficace ; l'EU limite sa concentration, à éviter pendant la grossesse.`},"aluminum chlorohydrate":{note:`Sel anti-transpirant ; le SCCS a jugé les utilisations actuelles sûres (2020).`},talc:{note:`Sûr pour la peau s'il est exempt d'amiante ; éviter la poudre inhalable près des poumons.`},"mineral oil":{note:`Occlusif ; la pureté importe (la qualité cosmétique est raffinée).`},"paraffinum liquidum":{note:`Huile minérale sous son nom INCI ; les qualités raffinées sont sûres.`},petrolatum:{note:`Occlusif ; sûr lorsqu'il est correctement raffiné (l'EU l'exige).`},lanolin:{note:`Dérivé de la laine ; efficace, mais c'est un allergène de contact connu.`},glycerin:{note:`Humectant qui fixe l'hydratation ; compte parmi les ingrédients les plus sûrs en cosmétique.`},"hyaluronic acid":{note:`Actif fixateur d'hydratation, très bien toléré.`},"sodium hyaluronate":{note:`Forme salée de l'acide hyaluronique ; bien toléré.`},panthenol:{note:`Provitamine B5 — véritablement revitalisant et à faible risque.`},niacinamide:{note:`Vitamine B3 — étayée par des preuves scientifiques et bien tolérée.`},tocopherol:{note:`Vitamine E antioxydante.`},ceramide:{note:`Lipides identiques à ceux de la peau ; soutien de la barrière cutanée.`}},r={ui:e,additives:t,inci:n};export{t as additives,r as default,n as inci,e as ui};